INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_media_01', 'go', 'viral', 'go viral', '바이럴이 되다', 'become', '"become viral"도 쓰이지만 go viral이 더 자연스럽고 자주 쓰여요.', 'The video went viral and got over ten million views in a week.', '그 영상은 바이럴이 되어 일주일 만에 천만 조회수를 넘었어요.', 'Her post went viral after a celebrity shared it.', '유명인이 공유한 후 그녀의 게시물이 바이럴이 됐어요.', 'B1', 'media', 1, 'viral social media video trending internet', 1),
('col_media_02', 'make', 'news', 'make news', '뉴스가 되다', 'do', '"do news"는 틀린 표현이에요. 뉴스에 나올 때는 make news를 써요.', 'The scandal made headlines and dominated the news for weeks.', '그 스캔들은 헤드라인을 장식하며 몇 주 동안 뉴스를 지배했어요.', 'A small local story unexpectedly made national news.', '작은 지역 소식이 뜻밖에 전국 뉴스가 됐어요.', 'B2', 'media', 2, 'news media headline coverage broadcast', 2),
('col_media_03', 'get', 'followers', 'get followers', '팔로워를 얻다', 'have', '"have followers"는 현재 상태이고, get은 새로 얻는 것을 강조해요.', 'She got thousands of followers overnight after a viral post.', '그녀는 바이럴 게시물 이후 하룻밤 만에 수천 명의 팔로워를 얻었어요.', 'How did you get so many followers so quickly?', '어떻게 그렇게 빨리 많은 팔로워를 얻었어요?', 'B1', 'media', 1, 'followers social media influencer content creator', 3),
('col_media_04', 'post', 'content', 'post content', '콘텐츠를 올리다', 'upload', '"upload"도 맞지만 post는 소셜 미디어에서 더 일상적으로 쓰여요.', 'She posts content every day to keep her audience engaged.', '그녀는 팔로워들의 참여를 유지하기 위해 매일 콘텐츠를 올려요.', 'He posts a variety of content — videos, photos, and stories.', '그는 영상, 사진, 스토리 등 다양한 콘텐츠를 올려요.', 'B1', 'media', 1, 'content social media posting influencer', 4),
('col_media_05', 'run', 'an ad', 'run an ad', '광고를 집행하다', 'make', '"make an ad"는 광고를 제작하는 것이고, run은 집행·게재하는 것이에요.', 'The company ran a targeted ad campaign on social media.', '회사는 소셜 미디어에서 타겟 광고 캠페인을 집행했어요.', 'They''re running ads on three different platforms this month.', '이번 달 세 개의 플랫폼에서 광고를 집행하고 있어요.', 'B2', 'media', 2, 'advertisement campaign digital media marketing', 5),
('col_media_06', 'keep', 'updated', 'keep updated', '최신 정보를 유지하다', 'stay', '"stay updated"도 맞지만 keep updated가 더 지속적인 뉘앙스예요.', 'Follow our page to keep updated on the latest news.', '최신 뉴스를 받아보려면 저희 페이지를 팔로우하세요.', 'She keeps updated by reading news apps every morning.', '그녀는 매일 아침 뉴스 앱을 읽으며 최신 정보를 유지해요.', 'B1', 'media', 2, 'updated news app information digital', 6),
('col_media_07', 'break', 'news', 'break news', '뉴스를 최초로 보도하다', 'report', '"report news"도 맞지만 break news는 최초로 보도하는 것을 강조해요.', 'The journalist broke the news about the government scandal.', '그 기자는 정부 스캔들 뉴스를 최초로 보도했어요.', 'Which outlet was first to break the story?', '어느 매체가 그 이야기를 최초로 보도했어요?', 'C1', 'media', 2, 'breaking news journalist scoop exclusive', 7),
('col_media_08', 'hold', 'attention', 'hold attention', '관심을 유지하다', 'get', '"get attention"은 처음 끌 때이고, hold는 계속 유지하는 것이에요.', 'The documentary held the audience''s attention from start to finish.', '그 다큐멘터리는 처음부터 끝까지 관객의 관심을 유지했어요.', 'It''s hard to hold people''s attention on social media for long.', '소셜 미디어에서 사람들의 관심을 오래 유지하기는 어려워요.', 'B2', 'media', 2, 'attention audience engagement content media', 8),
('col_media_09', 'make', 'a headline', 'make a headline', '헤드라인을 장식하다', 'do', '"do a headline"은 틀린 표현이에요. 헤드라인에 나올 때는 make를 써요.', 'The scandal made the front page headline of every major newspaper.', '그 스캔들은 모든 주요 신문의 1면 헤드라인을 장식했어요.', 'Her performance made headlines across the entertainment media.', '그녀의 공연은 엔터테인먼트 미디어 전반의 헤드라인을 장식했어요.', 'B2', 'media', 2, 'headline news media front page report', 9),
('col_media_10', 'get', 'trending', 'get trending', '트렌딩이 되다', 'become', '"become trending"은 어색해요. 트렌딩이 될 때는 get trending을 써요.', 'The hashtag got trending within hours of the announcement.', '그 해시태그는 발표 후 몇 시간 만에 트렌딩이 됐어요.', 'Her music video got trending after a big influencer shared it.', '유명 인플루언서가 공유한 후 그녀의 뮤직비디오가 트렌딩이 됐어요.', 'B1', 'media', 1, 'trending social media viral hashtag internet', 10),
('col_media_11', 'stream', 'content', 'stream content', '콘텐츠를 스트리밍하다', 'watch', '"watch content"도 맞지만 stream은 온라인 동영상 서비스를 강조해요.', 'Millions of people stream content on platforms like Netflix daily.', '수백만 명이 매일 넷플릭스 같은 플랫폼에서 콘텐츠를 스트리밍해요.', 'She streams live content every Friday evening.', '그녀는 매주 금요일 저녁에 라이브 콘텐츠를 스트리밍해요.', 'B1', 'media', 1, 'streaming netflix content watching online', 11),
('col_media_12', 'build', 'an audience', 'build an audience', '팬층을 쌓다', 'get', '"get an audience"도 맞지만 build는 점진적으로 쌓아가는 뉘앙스예요.', 'It takes time and consistency to build an audience from scratch.', '처음부터 팬층을 쌓으려면 시간과 일관성이 필요해요.', 'She built a loyal audience by posting authentic content.', '그녀는 진솔한 콘텐츠를 올림으로써 충성스러운 팬층을 쌓았어요.', 'B2', 'media', 2, 'audience followers creator social media', 12),
('col_media_13', 'cover', 'a story', 'cover a story', '기사를 취재하다', 'report', '"report a story"도 맞지만 cover는 심층 취재를 강조해요.', 'The reporter was sent to cover the story on the ground.', '기자는 현장에서 그 이야기를 취재하기 위해 파견됐어요.', 'The magazine has been covering this story for three months.', '그 잡지는 3개월 동안 이 이야기를 취재해 왔어요.', 'B2', 'media', 2, 'journalism coverage story reporter news', 13),
('col_media_14', 'go', 'live', 'go live', '라이브 방송을 하다', 'start', '"start a broadcast"도 맞지만 go live는 소셜 미디어와 방송에서 자주 쓰여요.', 'She went live on Instagram to announce the news.', '그녀는 뉴스를 발표하기 위해 인스타그램에서 라이브 방송을 했어요.', 'The channel goes live every day at 7 p.m.', '그 채널은 매일 오후 7시에 라이브 방송을 해요.', 'B1', 'media', 1, 'live stream broadcast social media real-time', 14),
('col_media_15', 'share', 'a post', 'share a post', '게시물을 공유하다', 'forward', '"forward"는 이메일에 더 잘 쓰여요. 소셜 미디어에서는 share를 써요.', 'She shared the post and it reached thousands of people.', '그녀가 게시물을 공유하자 수천 명에게 도달했어요.', 'Could you share the post to help spread the word?', '소식을 퍼뜨리는 데 도움이 되도록 게시물을 공유해 줄 수 있어요?', 'A2', 'media', 1, 'share post social media spread content', 15),
('col_media_16', 'gain', 'exposure', 'gain exposure', '노출을 얻다', 'get', '"get exposure"도 맞지만 gain은 점차 쌓아가는 뉘앙스예요.', 'The small brand gained huge exposure after a celebrity mention.', '그 소규모 브랜드는 유명인의 언급 이후 엄청난 노출을 얻었어요.', 'Being featured in a popular magazine helped them gain exposure.', '인기 잡지에 실리는 것이 그들이 노출을 얻는 데 도움이 됐어요.', 'C1', 'media', 3, 'exposure publicity brand media recognition', 16),
('col_media_17', 'edit', 'footage', 'edit footage', '영상을 편집하다', 'cut', '"cut footage"는 일부만 의미해요. 영상 편집은 edit footage를 써요.', 'He spent hours editing footage for the documentary.', '그는 다큐멘터리 영상을 편집하는 데 몇 시간을 보냈어요.', 'She edits all her own footage before uploading to YouTube.', '그녀는 유튜브에 업로드하기 전에 자신의 영상을 직접 편집해요.', 'B2', 'media', 2, 'editing video footage post-production content', 17),
('col_media_18', 'broadcast', 'live', 'broadcast live', '생방송하다', 'stream', '"stream live"도 맞지만 broadcast는 더 전통적인 방송 표현이에요.', 'The event will be broadcast live on national television.', '그 행사는 전국 방송에서 생방송으로 방영될 예정이에요.', 'They broadcast live from the scene of the disaster.', '그들은 재해 현장에서 생방송을 했어요.', 'B2', 'media', 2, 'broadcast live TV news coverage', 18),
('col_media_19', 'reach', 'an audience', 'reach an audience', '청중에게 닿다', 'get', '"get an audience"도 맞지만 reach는 메시지가 도달하는 것을 강조해요.', 'Social media allows creators to reach a global audience.', '소셜 미디어는 창작자들이 전 세계 청중에게 닿을 수 있게 해줘요.', 'The campaign reached a much wider audience than expected.', '그 캠페인은 예상보다 훨씬 더 많은 청중에게 닿았어요.', 'B2', 'media', 2, 'audience reach media campaign global', 19),
('col_media_20', 'pull', 'a story', 'pull a story', '기사를 내리다', 'delete', '"delete a story"는 온라인에서 쓰이고, pull a story는 방송/인쇄에서 더 쓰여요.', 'The editor decided to pull the story due to legal concerns.', '편집장은 법적 우려로 인해 기사를 내리기로 결정했어요.', 'The station pulled the story after verifying the facts were wrong.', '방송국은 사실이 틀렸음을 확인한 후 그 기사를 내렸어요.', 'C1', 'media', 3, 'journalism retract story editorial media', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_environment_01', 'take', 'action', 'take action', '조치를 취하다', 'make', '"make action"은 틀린 표현이에요. 조치를 취할 때는 take를 써요.', 'Governments need to take action on climate change immediately.', '정부는 즉시 기후 변화에 대한 조치를 취해야 해요.', 'We can all take action to reduce our carbon footprint.', '우리 모두 탄소 발자국을 줄이기 위한 조치를 취할 수 있어요.', 'B1', 'environment', 1, 'action climate environment green policy', 1),
('col_environment_02', 'make', 'a difference', 'make a difference', '변화를 만들다', 'do', '"do a difference"는 틀린 표현이에요. 변화를 일으킬 때는 make를 써요.', 'Even small changes in daily habits can make a big difference.', '일상 습관의 작은 변화도 큰 차이를 만들 수 있어요.', 'Choosing to recycle makes a difference for the planet.', '재활용을 선택하는 것이 지구를 위해 변화를 만들어요.', 'B1', 'environment', 1, 'difference impact environment change green', 2),
('col_environment_03', 'reduce', 'emissions', 'reduce emissions', '배출량을 줄이다', 'decrease', '"decrease emissions"도 맞지만 reduce가 더 자주 쓰이는 환경 표현이에요.', 'The government has pledged to reduce carbon emissions by 50% by 2030.', '정부는 2030년까지 탄소 배출량을 50% 줄이겠다고 약속했어요.', 'Electric vehicles can help reduce emissions in urban areas.', '전기 자동차는 도시 지역의 배출량을 줄이는 데 도움이 될 수 있어요.', 'B2', 'environment', 1, 'emissions carbon reduction climate electric', 3),
('col_environment_04', 'break', 'a habit', 'break a habit', '(나쁜) 습관을 끊다', 'stop', '"stop a habit"도 맞지만 break a habit은 오래된 습관을 끊는 뉘앙스예요.', 'Breaking the habit of using single-use plastics takes effort.', '일회용 플라스틱 사용 습관을 끊는 데는 노력이 필요해요.', 'We need to break the habit of driving short distances.', '짧은 거리를 차로 이동하는 습관을 끊어야 해요.', 'B2', 'environment', 2, 'habit change recycle green lifestyle', 4),
('col_environment_05', 'run', 'a campaign', 'run a campaign', '캠페인을 진행하다', 'do', '"do a campaign"은 어색해요. 캠페인을 운영할 때는 run을 써요.', 'The NGO ran a successful campaign to ban plastic bags.', '그 NGO는 비닐봉지 금지를 위한 성공적인 캠페인을 진행했어요.', 'They''re running a recycling awareness campaign this month.', '이번 달 재활용 인식 캠페인을 진행하고 있어요.', 'B2', 'environment', 2, 'campaign environment NGO awareness green', 5),
('col_environment_06', 'hold', 'a protest', 'hold a protest', '시위를 열다', 'make', '"make a protest"는 어색해요. 시위를 개최할 때는 hold를 써요.', 'Activists held a protest outside the parliament building.', '활동가들은 의회 건물 밖에서 시위를 열었어요.', 'Thousands of young people held protests demanding climate action.', '수천 명의 젊은이들이 기후 행동을 요구하며 시위를 열었어요.', 'B2', 'environment', 2, 'protest climate rally march environment', 6),
('col_environment_07', 'make', 'an impact', 'make an impact', '영향을 미치다', 'do', '"do an impact"는 틀린 표현이에요. 영향을 줄 때는 make an impact를 써요.', 'Individual choices can make a real impact on the environment.', '개인의 선택이 환경에 실질적인 영향을 미칠 수 있어요.', 'She wanted to make an impact through sustainable fashion.', '그녀는 지속 가능한 패션을 통해 영향을 미치고 싶었어요.', 'B2', 'environment', 2, 'impact sustainable environment change effect', 7),
('col_environment_08', 'get', 'involved', 'get involved', '참여하다', 'join', '"join"도 맞지만 get involved는 적극적으로 참여하는 뉘앙스예요.', 'Anyone can get involved in local environmental projects.', '누구나 지역 환경 프로젝트에 참여할 수 있어요.', 'She got involved in a beach clean-up volunteer program.', '그녀는 해변 청소 자원봉사 프로그램에 참여했어요.', 'B1', 'environment', 1, 'volunteer environment community involved green', 8),
('col_environment_09', 'set', 'targets', 'set targets', '목표를 설정하다', 'make', '"make targets"는 어색해요. 환경 목표를 설정할 때는 set을 써요.', 'The UN set ambitious targets to limit global warming to 1.5°C.', '유엔은 지구 온난화를 1.5°C로 제한하는 야심 찬 목표를 설정했어요.', 'The company set targets to achieve net-zero emissions by 2040.', '회사는 2040년까지 탄소 중립 배출을 달성하는 목표를 설정했어요.', 'B2', 'environment', 2, 'targets climate emission goal policy', 9),
('col_environment_10', 'conserve', 'energy', 'conserve energy', '에너지를 절약하다', 'save', '"save energy"도 맞지만 conserve는 환경 맥락에서 더 격식 있는 표현이에요.', 'Turn off appliances when not in use to conserve energy.', '에너지를 절약하기 위해 사용하지 않을 때는 가전제품을 끄세요.', 'Solar panels help conserve energy and reduce electricity bills.', '태양열 패널은 에너지 절약과 전기 요금 절감에 도움이 돼요.', 'B2', 'environment', 2, 'energy conservation solar panel electricity', 10),
('col_environment_11', 'protect', 'biodiversity', 'protect biodiversity', '생물 다양성을 보호하다', 'save', '"save biodiversity"도 맞지만 protect는 체계적인 보호를 강조해요.', 'We must protect biodiversity before it''s too late.', '너무 늦기 전에 생물 다양성을 보호해야 해요.', 'The new nature reserve was created to protect biodiversity.', '새 자연 보호구역은 생물 다양성을 보호하기 위해 만들어졌어요.', 'C1', 'environment', 3, 'biodiversity nature wildlife protection conservation', 11),
('col_environment_12', 'tackle', 'pollution', 'tackle pollution', '오염을 해결하다', 'solve', '"solve pollution"도 맞지만 tackle은 적극적으로 맞서는 뉘앙스예요.', 'Cities are trying innovative ways to tackle air pollution.', '도시들은 대기 오염을 해결하기 위한 혁신적인 방법을 시도하고 있어요.', 'The government introduced new laws to tackle ocean pollution.', '정부는 해양 오염을 해결하기 위한 새로운 법률을 도입했어요.', 'B2', 'environment', 2, 'pollution tackling air water environment policy', 12),
('col_environment_13', 'switch', 'to renewables', 'switch to renewables', '재생에너지로 전환하다', 'change', '"change to renewables"도 맞지만 switch to는 전환을 강조해요.', 'The company plans to switch to renewable energy by 2025.', '회사는 2025년까지 재생에너지로 전환할 계획이에요.', 'Many households are switching to solar power to cut costs.', '많은 가정이 비용을 절감하기 위해 태양광으로 전환하고 있어요.', 'B2', 'environment', 2, 'renewable energy switch solar wind power', 13),
('col_environment_14', 'raise', 'awareness', 'raise awareness', '인식을 높이다', 'increase', '"increase awareness"도 맞지만 raise awareness가 더 자주 쓰여요.', 'The documentary raised awareness about plastic pollution.', '그 다큐멘터리는 플라스틱 오염에 대한 인식을 높였어요.', 'She uses social media to raise awareness about climate change.', '그녀는 기후 변화에 대한 인식을 높이기 위해 소셜 미디어를 이용해요.', 'B2', 'environment', 1, 'awareness environment campaign education climate', 14),
('col_environment_15', 'adopt', 'sustainable practices', 'adopt sustainable practices', '지속 가능한 관행을 채택하다', 'use', '"use sustainable practices"도 맞지만 adopt는 공식적인 도입을 강조해요.', 'More companies are adopting sustainable practices to reduce their footprint.', '더 많은 기업들이 발자국을 줄이기 위해 지속 가능한 관행을 채택하고 있어요.', 'The school adopted sustainable practices like composting and recycling.', '학교는 퇴비화 및 재활용과 같은 지속 가능한 관행을 채택했어요.', 'C1', 'environment', 3, 'sustainable practices green business environment', 15),
('col_environment_16', 'cut', 'down on waste', 'cut down on waste', '폐기물을 줄이다', 'reduce', '"reduce waste"도 맞지만 cut down on은 더 생활밀착형 표현이에요.', 'We can all cut down on food waste by planning meals ahead.', '식사를 미리 계획함으로써 음식 낭비를 줄일 수 있어요.', 'The company cut down on packaging waste by switching to reusable materials.', '회사는 재사용 가능한 재료로 전환하여 포장 폐기물을 줄였어요.', 'B2', 'environment', 2, 'waste reduction recycling packaging green', 16),
('col_environment_17', 'go', 'green', 'go green', '친환경적으로 되다', 'become', '"become green"도 맞지만 go green이 더 구어체적이에요.', 'More and more households are going green with solar panels.', '점점 더 많은 가정이 태양열 패널로 친환경적이 되고 있어요.', 'The company pledged to go green within the next five years.', '회사는 향후 5년 내에 친환경적으로 전환하겠다고 약속했어요.', 'B1', 'environment', 1, 'green sustainable eco-friendly lifestyle energy', 17),
('col_environment_18', 'support', 'conservation efforts', 'support conservation efforts', '보존 노력을 지지하다', 'help', '"help conservation efforts"도 맞지만 support는 더 체계적인 지원을 강조해요.', 'You can support conservation efforts by donating to wildlife charities.', '야생동물 자선단체에 기부함으로써 보존 노력을 지지할 수 있어요.', 'The government committed to supporting conservation efforts in national parks.', '정부는 국립공원에서의 보존 노력을 지지하겠다고 약속했어요.', 'C1', 'environment', 3, 'conservation wildlife national park donation', 18),
('col_environment_19', 'face', 'extinction', 'face extinction', '멸종 위기에 처하다', 'become', '"become extinct"도 맞지만 face extinction은 위기를 마주하는 과정을 강조해요.', 'Many species are facing extinction due to habitat destruction.', '많은 종들이 서식지 파괴로 인해 멸종 위기에 처해 있어요.', 'Without protection, the snow leopard could face extinction within decades.', '보호 없이는 눈표범이 수십 년 내에 멸종 위기에 처할 수 있어요.', 'C1', 'environment', 3, 'extinction endangered species wildlife habitat', 19),
('col_environment_20', 'offset', 'carbon', 'offset carbon', '탄소를 상쇄하다', 'reduce', 'offset은 다른 곳에서 줄여서 배출을 보상하는 뉘앙스이고, reduce는 직접 줄이는 것이에요.', 'You can offset your carbon from flying by planting trees.', '나무 심기로 비행으로 인한 탄소를 상쇄할 수 있어요.', 'The company offsets its carbon emissions through renewable energy projects.', '회사는 재생에너지 프로젝트를 통해 탄소 배출을 상쇄해요.', 'C1', 'environment', 3, 'carbon offset footprint climate tree planting', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_economy_01', 'make', 'a profit', 'make a profit', '이익을 내다', 'do', '"do a profit"은 틀린 표현이에요. 이익을 창출할 때는 make를 써요.', 'The startup finally made a profit after two years of losses.', '그 스타트업은 2년간의 적자 끝에 마침내 이익을 냈어요.', 'They made a substantial profit on the sale of the property.', '그들은 부동산 매각으로 상당한 이익을 냈어요.', 'B2', 'economy', 1, 'profit business finance revenue success', 1),
('col_economy_02', 'take', 'a risk', 'take a risk', '위험을 감수하다', 'do', '"do a risk"는 틀린 표현이에요. 위험을 감수할 때는 take를 써요.', 'Every entrepreneur has to take risks to grow their business.', '모든 기업가는 사업을 성장시키기 위해 위험을 감수해야 해요.', 'She took a calculated risk and it paid off in the end.', '그녀는 계산된 위험을 감수했고 결국 성과를 거뒀어요.', 'B2', 'economy', 2, 'risk investment business decision finance', 2),
('col_economy_03', 'run', 'a business', 'run a business', '사업을 운영하다', 'make', '"make a business"는 사업을 만드는 것이고, run은 운영하는 것이에요.', 'She has been running a small bakery business for five years.', '그녀는 5년 동안 작은 베이커리 사업을 운영해 왔어요.', 'Running a business during a recession is very challenging.', '경기 침체 기간에 사업을 운영하는 것은 매우 도전적이에요.', 'B2', 'economy', 1, 'business operation management entrepreneur', 3),
('col_economy_04', 'keep', 'costs down', 'keep costs down', '비용을 낮추다', 'reduce', '"reduce costs"도 맞지만 keep costs down은 지속적으로 낮은 수준을 유지하는 뉘앙스예요.', 'The company introduced automation to keep production costs down.', '회사는 생산 비용을 낮추기 위해 자동화를 도입했어요.', 'We need to find ways to keep our operating costs down.', '운영 비용을 낮게 유지할 방법을 찾아야 해요.', 'C1', 'economy', 2, 'costs reduction budget business finance', 4),
('col_economy_05', 'break', 'even', 'break even', '손익분기점에 도달하다', 'reach', '"reach even"은 틀린 표현이에요. 손익분기점을 맞출 때는 break even을 써요.', 'Most startups take at least two years to break even.', '대부분의 스타트업은 손익분기점에 도달하는 데 최소 2년이 걸려요.', 'We broke even on the project, which we considered a success.', '우리는 프로젝트에서 손익분기점을 맞췄는데, 그것을 성공으로 여겼어요.', 'C1', 'economy', 2, 'break even business profit loss finance', 5),
('col_economy_06', 'hold', 'shares', 'hold shares', '주식을 보유하다', 'have', '"have shares"도 맞지만 hold shares는 지속적인 보유를 강조해요.', 'She holds shares in several major tech companies.', '그녀는 여러 주요 기술 기업의 주식을 보유하고 있어요.', 'It''s risky to hold too many shares in a single company.', '한 회사에 너무 많은 주식을 보유하는 것은 위험해요.', 'C1', 'economy', 3, 'shares stocks investment portfolio finance', 6),
('col_economy_07', 'make', 'an investment', 'make an investment', '투자하다', 'do', '"do an investment"는 틀린 표현이에요. 투자할 때는 make를 써요.', 'He made a significant investment in renewable energy.', '그는 재생에너지에 상당한 투자를 했어요.', 'It''s important to make wise investments for the future.', '미래를 위해 현명한 투자를 하는 것이 중요해요.', 'B2', 'economy', 2, 'investment finance business growth return', 7),
('col_economy_08', 'get', 'a loan', 'get a loan', '대출을 받다', 'take', '"take a loan"도 맞지만 get a loan이 더 구어체적이에요.', 'She got a loan from the bank to start her business.', '그녀는 사업을 시작하기 위해 은행에서 대출을 받았어요.', 'It can be difficult to get a loan with a low credit score.', '신용 점수가 낮으면 대출받기 어려울 수 있어요.', 'B2', 'economy', 2, 'loan bank borrowing credit finance', 8),
('col_economy_09', 'set', 'a budget', 'set a budget', '예산을 세우다', 'make', '"make a budget"도 쓰이지만 set a budget이 더 격식 있어요.', 'The finance team set a budget for the new quarter.', '재무팀은 새 분기를 위한 예산을 세웠어요.', 'You should set a budget before you start spending on the event.', '행사 지출을 시작하기 전에 예산을 세워야 해요.', 'B2', 'economy', 1, 'budget finance planning money business', 9),
('col_economy_10', 'pay', 'taxes', 'pay taxes', '세금을 내다', 'give', '"give taxes"는 틀린 표현이에요. 세금을 낼 때는 pay를 써요.', 'Every citizen is required to pay taxes by law.', '모든 시민은 법에 따라 세금을 내야 해요.', 'He always pays his taxes on time to avoid penalties.', '그는 항상 벌금을 피하기 위해 제때 세금을 내요.', 'B1', 'economy', 1, 'taxes payment government finance citizen', 10),
('col_economy_11', 'face', 'a recession', 'face a recession', '경기 침체에 직면하다', 'have', '"have a recession"도 쓰이지만 face는 어려운 상황에 직면하는 뉘앙스예요.', 'Many countries faced a recession after the global financial crisis.', '많은 나라들이 글로벌 금융 위기 이후 경기 침체에 직면했어요.', 'Small businesses suffer most when a country faces a recession.', '나라가 경기 침체에 직면할 때 소규모 사업체가 가장 큰 타격을 받아요.', 'C1', 'economy', 2, 'recession economy crisis finance decline', 11),
('col_economy_12', 'boost', 'the economy', 'boost the economy', '경제를 활성화하다', 'increase', '"increase the economy"는 어색해요. 경제 활성화에는 boost를 써요.', 'The government introduced tax cuts to boost the economy.', '정부는 경제를 활성화하기 위해 세금 감면을 도입했어요.', 'Tourism plays a key role in boosting the local economy.', '관광업은 지역 경제 활성화에 중요한 역할을 해요.', 'B2', 'economy', 2, 'economy growth boost government GDP', 12),
('col_economy_13', 'generate', 'revenue', 'generate revenue', '수익을 창출하다', 'make', '"make revenue"도 쓰이지만 generate는 다양한 경로로 창출하는 뉘앙스예요.', 'The app generates revenue through subscriptions and ads.', '그 앱은 구독과 광고를 통해 수익을 창출해요.', 'New products helped the company generate more revenue.', '신제품이 회사가 더 많은 수익을 창출하는 데 도움이 됐어요.', 'C1', 'economy', 3, 'revenue income business finance stream', 13),
('col_economy_14', 'cut', 'spending', 'cut spending', '지출을 삭감하다', 'reduce', '"reduce spending"도 맞지만 cut은 더 적극적인 삭감을 의미해요.', 'The government announced plans to cut public spending.', '정부는 공공 지출 삭감 계획을 발표했어요.', 'Businesses often cut spending during times of uncertainty.', '기업들은 불확실한 시기에 종종 지출을 삭감해요.', 'B2', 'economy', 2, 'spending cut budget austerity finance', 14),
('col_economy_15', 'raise', 'interest rates', 'raise interest rates', '금리를 올리다', 'increase', '"increase interest rates"도 맞지만 raise는 중앙은행의 조치를 강조해요.', 'The central bank raised interest rates to control inflation.', '중앙은행은 인플레이션을 통제하기 위해 금리를 올렸어요.', 'Raising interest rates can slow down economic growth.', '금리를 올리면 경제 성장이 둔화될 수 있어요.', 'C1', 'economy', 3, 'interest rate bank inflation finance policy', 15),
('col_economy_16', 'run', 'a deficit', 'run a deficit', '적자를 기록하다', 'have', '"have a deficit"도 맞지만 run a deficit은 지속적인 상태를 강조해요.', 'The country has been running a budget deficit for several years.', '그 나라는 몇 년간 재정 적자를 기록하고 있어요.', 'The company ran a deficit in its first year of operation.', '회사는 운영 첫 해에 적자를 기록했어요.', 'C1', 'economy', 3, 'deficit budget government finance loss', 16),
('col_economy_17', 'attract', 'investment', 'attract investment', '투자를 유치하다', 'get', '"get investment"도 맞지만 attract는 적극적으로 끌어들이는 뉘앙스예요.', 'The city has worked hard to attract foreign investment.', '그 도시는 외국 투자를 유치하기 위해 열심히 노력했어요.', 'Good infrastructure and low taxes help attract investment.', '좋은 인프라와 낮은 세금이 투자를 유치하는 데 도움이 돼요.', 'C1', 'economy', 3, 'investment attract foreign business economy', 17),
('col_economy_18', 'drive', 'growth', 'drive growth', '성장을 이끌다', 'make', '"make growth"는 틀린 표현이에요. 성장을 주도할 때는 drive를 써요.', 'Innovation is what drives growth in the technology sector.', '혁신이 기술 분야의 성장을 이끄는 것이에요.', 'The new policy is expected to drive economic growth.', '새 정책이 경제 성장을 이끌 것으로 기대돼요.', 'C1', 'economy', 3, 'growth economic drive GDP business', 18),
('col_economy_19', 'go', 'bankrupt', 'go bankrupt', '파산하다', 'become', '"become bankrupt"도 맞지만 go bankrupt가 훨씬 더 자주 쓰여요.', 'Several small businesses went bankrupt during the pandemic.', '여러 소규모 사업체가 팬데믹 기간에 파산했어요.', 'The company went bankrupt after years of poor management.', '그 회사는 수년간의 경영 부실 끝에 파산했어요.', 'B2', 'economy', 2, 'bankrupt business failure closure finance', 19),
('col_economy_20', 'control', 'inflation', 'control inflation', '인플레이션을 통제하다', 'reduce', '"reduce inflation"도 맞지만 control은 상승을 막는 것을 강조해요.', 'Central banks use interest rates as a tool to control inflation.', '중앙은행은 인플레이션을 통제하는 수단으로 금리를 사용해요.', 'It has been difficult to control inflation since the energy crisis.', '에너지 위기 이후 인플레이션을 통제하기가 어려웠어요.', 'C1', 'economy', 3, 'inflation control price economy monetary policy', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_culture_01', 'put', 'on a performance', 'put on a performance', '공연을 선보이다', 'make', '"make a performance"는 어색해요. 공연을 무대에 올릴 때는 put on을 써요.', 'The theater company put on a spectacular performance last night.', '극단은 어젯밤 화려한 공연을 선보였어요.', 'The school put on a performance of Romeo and Juliet.', '학교는 로미오와 줄리엣 공연을 선보였어요.', 'B2', 'culture', 1, 'performance theater stage show arts', 1),
('col_culture_02', 'hold', 'an exhibition', 'hold an exhibition', '전시회를 열다', 'make', '"make an exhibition"은 창피를 당한다는 뜻이에요. 전시를 열 때는 hold를 써요.', 'The gallery is holding an exhibition of contemporary Korean art.', '갤러리는 현대 한국 예술 전시회를 열고 있어요.', 'They held an exhibition celebrating local artists.', '그들은 지역 예술가들을 기리는 전시회를 열었어요.', 'B1', 'culture', 1, 'exhibition gallery art museum show', 2),
('col_culture_03', 'make', 'art', 'make art', '예술 작품을 만들다', 'do', '"do art"도 쓰이지만 make art는 창작 행위를 더 강조해요.', 'She makes art that challenges social norms.', '그녀는 사회적 규범에 도전하는 예술 작품을 만들어요.', 'Making art can be a powerful way to process emotions.', '예술 작품을 만드는 것은 감정을 처리하는 강력한 방법이 될 수 있어요.', 'B1', 'culture', 2, 'art studio creating painting artist', 3),
('col_culture_04', 'give', 'a concert', 'give a concert', '콘서트를 열다', 'make', '"make a concert"는 틀린 표현이에요. 콘서트를 개최할 때는 give를 써요.', 'The orchestra gave a stunning concert at the concert hall.', '오케스트라는 콘서트 홀에서 감동적인 콘서트를 열었어요.', 'She gave her first major concert in front of 5,000 people.', '그녀는 5,000명 앞에서 첫 번째 주요 콘서트를 열었어요.', 'B1', 'culture', 1, 'concert music performance hall singer', 4),
('col_culture_05', 'break', 'records', 'break records', '기록을 깨다', 'set', '기록을 새로 세울 때는 set, 기존 기록을 뛰어넘을 때는 break를 써요.', 'The film broke box office records in its opening weekend.', '그 영화는 개봉 주말 박스오피스 기록을 깼어요.', 'The band broke attendance records with their world tour.', '그 밴드는 월드 투어로 관객 수 기록을 깼어요.', 'B1', 'culture', 2, 'record breaking music film box office', 5),
('col_culture_06', 'take', 'inspiration', 'take inspiration', '영감을 얻다', 'get', '"get inspiration"도 맞지만 take inspiration은 의도적으로 받아들이는 뉘앙스예요.', 'She takes inspiration from Korean traditional patterns in her designs.', '그녀는 디자인에서 한국 전통 문양에서 영감을 얻어요.', 'The artist took inspiration from the landscape during her travels.', '그 예술가는 여행 중에 풍경에서 영감을 얻었어요.', 'B2', 'culture', 2, 'inspiration art creative design culture', 6),
('col_culture_07', 'get', 'recognition', 'get recognition', '인정을 받다', 'receive', '"receive recognition"도 맞지만 get은 더 구어체적이에요.', 'She finally got the recognition she deserved for her work.', '그녀는 마침내 자신의 작업에 대한 마땅한 인정을 받았어요.', 'The young director got international recognition at Cannes.', '그 젊은 감독은 칸에서 국제적인 인정을 받았어요.', 'B2', 'culture', 2, 'recognition award achievement culture arts', 7),
('col_culture_08', 'keep', 'tradition', 'keep a tradition alive', '전통을 이어가다', 'save', '"save a tradition"도 쓰이지만 keep alive는 지속적인 유지를 강조해요.', 'The community works hard to keep its cultural traditions alive.', '그 공동체는 문화적 전통을 이어가기 위해 열심히 노력해요.', 'Festivals are a great way to keep traditional customs alive.', '축제는 전통적인 관습을 이어가는 훌륭한 방법이에요.', 'B2', 'culture', 2, 'tradition culture heritage community festival', 8),
('col_culture_09', 'run', 'a festival', 'run a festival', '축제를 진행하다', 'make', '"make a festival"은 어색해요. 축제를 운영할 때는 run을 써요.', 'The city has been running the film festival for over 30 years.', '그 도시는 30년 이상 영화제를 진행해 왔어요.', 'They run the cultural festival every autumn with community support.', '그들은 지역사회 지원으로 매년 가을 문화 축제를 진행해요.', 'B2', 'culture', 2, 'festival culture event running annual', 9),
('col_culture_10', 'make', 'history', 'make history', '역사를 만들다', 'do', '"do history"는 틀린 표현이에요. 역사적인 순간을 만들 때는 make를 써요.', 'She made history as the first woman to win the award.', '그녀는 그 상을 수상한 최초의 여성으로 역사를 만들었어요.', 'The performance made history at Carnegie Hall.', '그 공연은 카네기 홀에서 역사를 만들었어요.', 'B2', 'culture', 2, 'history milestone achievement culture arts', 10),
('col_culture_11', 'blend', 'cultures', 'blend cultures', '문화를 융합하다', 'mix', '"mix cultures"도 맞지만 blend는 더 자연스럽고 조화로운 융합을 강조해요.', 'Her cooking blends Korean and Italian culinary traditions.', '그녀의 요리는 한국과 이탈리아 요리 전통을 융합해요.', 'The city has always been a place where different cultures blend.', '그 도시는 항상 서로 다른 문화가 융합되는 곳이었어요.', 'C1', 'culture', 3, 'culture blend fusion diversity multicultural', 11),
('col_culture_12', 'celebrate', 'diversity', 'celebrate diversity', '다양성을 축하하다', 'support', '"support diversity"도 맞지만 celebrate는 더 적극적인 인정을 강조해요.', 'The festival was designed to celebrate cultural diversity.', '그 축제는 문화적 다양성을 축하하기 위해 기획됐어요.', 'Great cities celebrate diversity in all its forms.', '훌륭한 도시들은 다양한 형태의 다양성을 축하해요.', 'B2', 'culture', 2, 'diversity culture celebration inclusion society', 12),
('col_culture_13', 'preserve', 'heritage', 'preserve heritage', '유산을 보존하다', 'keep', '"keep heritage"는 어색해요. 문화유산을 보존할 때는 preserve를 써요.', 'It''s essential to preserve our cultural heritage for future generations.', '미래 세대를 위해 문화 유산을 보존하는 것이 필수적이에요.', 'The museum works to preserve local heritage through exhibitions.', '박물관은 전시를 통해 지역 유산을 보존하기 위해 노력해요.', 'B2', 'culture', 2, 'heritage preservation culture museum history', 13),
('col_culture_14', 'attend', 'a performance', 'attend a performance', '공연을 관람하다', 'go', '"go to a performance"도 맞지만 attend는 더 격식 있는 표현이에요.', 'We attended a breathtaking ballet performance at the national theater.', '우리는 국립 극장에서 숨막히는 발레 공연을 관람했어요.', 'She attends live performances whenever she can.', '그녀는 가능할 때마다 라이브 공연을 관람해요.', 'B1', 'culture', 2, 'performance theater concert attend arts', 14),
('col_culture_15', 'launch', 'an art project', 'launch an art project', '예술 프로젝트를 시작하다', 'start', '"start an art project"도 맞지만 launch는 공식적인 시작을 강조해요.', 'The artist launched a community art project in the city center.', '그 예술가는 시내 중심부에서 지역 사회 예술 프로젝트를 시작했어요.', 'The gallery is launching a new exhibition series next month.', '갤러리는 다음 달에 새로운 전시 시리즈를 시작해요.', 'B2', 'culture', 2, 'art project launch exhibition gallery start', 15),
('col_culture_16', 'draw', 'crowds', 'draw crowds', '군중을 끌어들이다', 'get', '"get crowds"도 맞지만 draw는 매력으로 끌어들이는 뉘앙스예요.', 'The street performer drew large crowds on the weekend.', '거리 공연자는 주말에 많은 군중을 끌어들였어요.', 'The new sculpture in the plaza draws crowds every day.', '광장의 새 조각품은 매일 군중을 끌어들여요.', 'B2', 'culture', 2, 'crowd attraction cultural event performance', 16),
('col_culture_17', 'debut', 'as', 'debut as', '~으로 데뷔하다', 'start', '"start as"도 맞지만 debut는 공식적인 첫 등장을 강조해요.', 'She debuted as a solo artist after leaving the group.', '그녀는 그룹을 떠난 후 솔로 아티스트로 데뷔했어요.', 'He debuted as a director with a critically acclaimed short film.', '그는 비평가들에게 호평을 받은 단편 영화로 감독으로 데뷔했어요.', 'B2', 'culture', 2, 'debut career artist solo performance', 17),
('col_culture_18', 'commission', 'a work', 'commission a work', '작품을 의뢰하다', 'order', '"order a work"도 쓰이지만 commission은 예술 작품 의뢰에 전문적인 표현이에요.', 'The museum commissioned a new sculpture for its entrance.', '박물관은 입구를 위한 새로운 조각 작품을 의뢰했어요.', 'She was commissioned to paint a mural for the city hall.', '그녀는 시청을 위한 벽화를 그리도록 의뢰받았어요.', 'C1', 'culture', 3, 'commission art mural sculpture gallery', 18),
('col_culture_19', 'appreciate', 'art', 'appreciate art', '예술을 감상하다', 'enjoy', '"enjoy art"도 맞지만 appreciate는 더 깊은 이해를 강조해요.', 'She learned to appreciate classical art during her studies.', '그녀는 학업 중에 고전 예술을 감상하는 법을 배웠어요.', 'Visiting museums is a wonderful way to appreciate different art forms.', '박물관을 방문하는 것은 다양한 예술 형태를 감상하는 훌륭한 방법이에요.', 'B2', 'culture', 2, 'art appreciation museum gallery culture', 19),
('col_culture_20', 'gain', 'cultural insight', 'gain cultural insight', '문화적 통찰을 얻다', 'get', '"get cultural insight"도 맞지만 gain은 점차 깊어지는 이해를 강조해요.', 'Traveling abroad is a great way to gain cultural insight.', '해외여행은 문화적 통찰을 얻는 훌륭한 방법이에요.', 'The exchange program helped students gain cultural insight.', '교환 프로그램은 학생들이 문화적 통찰을 얻는 데 도움이 됐어요.', 'C1', 'culture', 3, 'cultural insight travel exchange understanding', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_sports_01', 'break', 'a record', 'break a record', '기록을 깨다', 'set', '기록을 처음으로 세울 때는 set, 기존 기록을 뛰어넘을 때는 break를 써요.', 'She broke the world record for the 200m sprint.', '그녀는 200m 단거리 달리기 세계 기록을 깼어요.', 'He broke the national record three times in one season.', '그는 한 시즌에 세 번이나 국가 기록을 깼어요.', 'B1', 'sports', 1, 'record athlete sports sprint achievement', 1),
('col_sports_02', 'make', 'a comeback', 'make a comeback', '복귀하다, 재기하다', 'do', '"do a comeback"은 어색해요. 선수가 복귀할 때는 make a comeback을 써요.', 'After two years out with injury, she made an incredible comeback.', '부상으로 2년간 공백 후, 그녀는 놀라운 복귀를 했어요.', 'The veteran player made a comeback at the age of 35.', '그 베테랑 선수는 35세에 복귀했어요.', 'B2', 'sports', 1, 'comeback athlete return sports champion', 2),
('col_sports_03', 'take', 'the lead', 'take the lead', '선두에 서다', 'get', '"get the lead"도 쓰이지만 take the lead가 더 능동적인 뉘앙스예요.', 'The team took the lead in the second half and never looked back.', '팀은 후반전에 선두에 서고 나서 계속 앞서 나갔어요.', 'She took the lead at the halfway point and held it to the finish.', '그녀는 중반에 선두에 서서 결승선까지 유지했어요.', 'B1', 'sports', 1, 'lead race sports competition winning', 3),
('col_sports_04', 'get', 'injured', 'get injured', '부상을 입다', 'have', '"have an injury"도 맞지만 get injured는 부상이 발생하는 순간을 강조해요.', 'He got injured during training and missed the whole season.', '그는 훈련 중에 부상을 입어 시즌 전체를 놓쳤어요.', 'She got injured in the final match, which was devastating.', '그녀는 결승전에서 부상을 입어 정말 힘들었어요.', 'B1', 'sports', 1, 'injury sports athlete training pain', 4),
('col_sports_05', 'keep', 'fit', 'keep fit', '건강을 유지하다', 'stay', '"stay fit"도 맞지만 keep fit은 지속적인 노력을 강조해요.', 'Professional athletes work very hard to keep fit throughout the season.', '프로 운동선수들은 시즌 내내 건강을 유지하기 위해 매우 열심히 노력해요.', 'She keeps fit by swimming three times a week.', '그녀는 일주일에 세 번 수영을 해서 건강을 유지해요.', 'B1', 'sports', 1, 'fitness training health sports active', 5),
('col_sports_06', 'hold', 'a championship', 'hold a championship', '선수권 대회를 개최하다', 'make', '"make a championship"은 어색해요. 대회를 개최할 때는 hold를 써요.', 'The city will hold the national swimming championship next year.', '그 도시는 내년에 전국 수영 선수권 대회를 개최할 예정이에요.', 'The club has held the regional championship for five years running.', '클럽은 5년 연속으로 지역 선수권 대회를 개최해 왔어요.', 'B2', 'sports', 2, 'championship tournament sports hosting event', 6),
('col_sports_07', 'make', 'a tackle', 'make a tackle', '태클을 하다', 'do', '"do a tackle"은 어색해요. 축구에서 태클할 때는 make a tackle을 써요.', 'He made a clean tackle to win the ball back.', '그는 공을 되찾기 위해 깔끔한 태클을 했어요.', 'Making a reckless tackle in the penalty area is very risky.', '페널티 에어리어에서 무모한 태클을 하는 것은 매우 위험해요.', 'B2', 'sports', 2, 'tackle football soccer challenge sport', 7),
('col_sports_08', 'run', 'a marathon', 'run a marathon', '마라톤을 하다', 'do', '"do a marathon"도 쓰이지만 run a marathon이 훨씬 더 자연스러워요.', 'She trained for six months before running her first marathon.', '그녀는 첫 마라톤을 하기 전에 6개월 동안 훈련했어요.', 'He runs a marathon every year for charity.', '그는 자선 활동을 위해 매년 마라톤을 해요.', 'B1', 'sports', 1, 'marathon running race fitness endurance', 8),
('col_sports_09', 'give', 'a performance', 'give a performance', '경기력을 보여주다', 'do', '"do a performance"는 어색해요. 경기력을 선보일 때는 give를 써요.', 'The young gymnast gave a flawless performance at the World Championships.', '그 젊은 체조 선수는 세계 선수권 대회에서 완벽한 경기력을 선보였어요.', 'She gave the performance of her career in the Olympic final.', '그녀는 올림픽 결승에서 선수 생활 최고의 경기력을 선보였어요.', 'B2', 'sports', 2, 'performance athlete competition sports excellence', 9),
('col_sports_10', 'set', 'a record', 'set a record', '기록을 세우다', 'make', '"make a record"는 다른 의미예요. 새 기록을 세울 때는 set을 써요.', 'She set a new personal record at the national competition.', '그녀는 전국 대회에서 새 개인 기록을 세웠어요.', 'The swimmer set a world record that still stands today.', '그 수영 선수는 오늘날에도 여전히 유지되는 세계 기록을 세웠어요.', 'B1', 'sports', 1, 'record new personal best sports competition', 10),
('col_sports_11', 'win', 'a title', 'win a title', '타이틀을 따다', 'get', '"get a title"도 맞지만 win은 경쟁을 통해 획득한다는 뉘앙스예요.', 'The team won the league title for the third consecutive year.', '팀은 3년 연속으로 리그 타이틀을 땄어요.', 'She won the title after an intense match that went to overtime.', '그녀는 연장전까지 간 치열한 경기 끝에 타이틀을 땄어요.', 'B1', 'sports', 1, 'title championship win trophy sports', 11),
('col_sports_12', 'score', 'a goal', 'score a goal', '골을 넣다', 'make', '"make a goal"은 틀린 표현이에요. 축구에서 골을 넣을 때는 score를 써요.', 'He scored the winning goal in the final minute of the game.', '그는 경기 마지막 1분에 결승 골을 넣었어요.', 'She scored three goals in one game, completing a hat trick.', '그녀는 한 경기에서 세 골을 넣으며 해트트릭을 달성했어요.', 'A2', 'sports', 1, 'goal football soccer score match', 12),
('col_sports_13', 'train', 'hard', 'train hard', '열심히 훈련하다', 'practice', '"practice hard"도 맞지만 train hard는 체계적인 훈련을 강조해요.', 'You have to train hard every day if you want to reach the top.', '정상에 오르고 싶다면 매일 열심히 훈련해야 해요.', 'She trained hard for six months and it showed in her performance.', '그녀는 6개월 동안 열심히 훈련했고 경기력에서 그것이 드러났어요.', 'B1', 'sports', 1, 'training hard work athlete dedication sport', 13),
('col_sports_14', 'compete', 'in', 'compete in', '~에 출전하다', 'join', '"join a competition"도 맞지만 compete in은 실제 경쟁에 참가하는 것을 강조해요.', 'She competed in the Olympics for the first time at age 18.', '그녀는 18세에 처음으로 올림픽에 출전했어요.', 'He has competed in over 50 international tournaments.', '그는 50개 이상의 국제 토너먼트에 출전해 왔어요.', 'B2', 'sports', 2, 'competition tournament international athlete event', 14),
('col_sports_15', 'retire', 'from', 'retire from', '~에서 은퇴하다', 'stop', '"stop playing"도 맞지만 retire from은 공식적인 은퇴를 강조해요.', 'He retired from professional tennis at the age of 38.', '그는 38세에 프로 테니스에서 은퇴했어요.', 'She retired from competitive swimming after winning the gold medal.', '그녀는 금메달을 딴 후 경쟁 수영에서 은퇴했어요.', 'B2', 'sports', 2, 'retirement athlete career ending sports', 15),
('col_sports_16', 'suffer', 'a defeat', 'suffer a defeat', '패배를 당하다', 'lose', '"lose a match"도 맞지만 suffer a defeat는 더 격식 있는 표현이에요.', 'The team suffered a heavy defeat in the championship final.', '팀은 챔피언십 결승에서 큰 패배를 당했어요.', 'Suffering a defeat early in the season motivated them to improve.', '시즌 초반의 패배가 그들이 성장하도록 동기를 부여했어요.', 'B2', 'sports', 2, 'defeat loss match sports competition', 16),
('col_sports_17', 'reach', 'the final', 'reach the final', '결승에 진출하다', 'go', '"go to the final"도 맞지만 reach the final은 대회를 통해 나아가는 뉘앙스예요.', 'It was the first time the club had reached the final.', '그 클럽이 결승에 진출한 것은 처음이었어요.', 'She reached the final of the Grand Slam tournament for the second time.', '그녀는 두 번째로 그랜드 슬램 토너먼트 결승에 진출했어요.', 'B2', 'sports', 2, 'final tournament sports competition round', 17),
('col_sports_18', 'put', 'in a performance', 'put in a performance', '경기에서 보여주다', 'make', '"make a performance"는 어색해요. 특정 경기에서의 수행을 표현할 때는 put in을 써요.', 'He really put in a strong performance during the semifinals.', '그는 준결승에서 정말 강한 경기력을 선보였어요.', 'She put in a world-class performance under incredible pressure.', '그녀는 엄청난 압박 속에서 세계 수준의 경기력을 보여줬어요.', 'C1', 'sports', 3, 'performance athlete sport match pressure', 18),
('col_sports_19', 'beat', 'an opponent', 'beat an opponent', '상대를 이기다', 'win', '"win an opponent"는 틀린 표현이에요. 상대를 이길 때는 beat를 써요.', 'She beat her opponent in straight sets to win the trophy.', '그녀는 3세트 연속으로 상대를 이겨 트로피를 차지했어요.', 'He has beaten his main opponent six times in a row.', '그는 주요 상대를 연속으로 6번 이겼어요.', 'B1', 'sports', 1, 'opponent match win defeat sport', 19),
('col_sports_20', 'pull', 'out of', 'pull out of', '~에서 기권하다', 'leave', '"leave a competition"도 맞지만 pull out of는 예상치 못한 기권을 강조해요.', 'She pulled out of the tournament due to a knee injury.', '그녀는 무릎 부상으로 인해 토너먼트에서 기권했어요.', 'He was forced to pull out of the race at the last minute.', '그는 막판에 어쩔 수 없이 경기를 기권해야 했어요.', 'B2', 'sports', 2, 'withdrawal sports injury retirement race', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_discussion_01', 'raise', 'a point', 'raise a point', '요점을 제기하다', 'make', '"make a point"도 맞지만 raise a point는 새로운 관점을 꺼내는 뉘앙스예요.', 'She raised an important point about the budget during the meeting.', '그녀는 회의 중에 예산에 대한 중요한 요점을 제기했어요.', 'He raised several valid points that changed the direction of the debate.', '그는 토론의 방향을 바꾸는 여러 타당한 요점을 제기했어요.', 'B1', 'discussion', 1, 'discussion meeting debate point talking', 1),
('col_discussion_02', 'reach', 'a consensus', 'reach a consensus', '합의에 이르다', 'get', '"get a consensus"도 쓰이지만 reach는 노력 끝에 도달하는 뉘앙스예요.', 'After two hours of debate, the group reached a consensus.', '두 시간의 토론 끝에 그룹은 합의에 이르렀어요.', 'It was difficult to reach a consensus on such a controversial topic.', '그렇게 논쟁적인 주제에서 합의에 이르기가 어려웠어요.', 'B2', 'discussion', 2, 'agreement consensus discussion team', 2),
('col_discussion_03', 'put forward', 'an argument', 'put forward an argument', '주장을 내놓다', 'say', '"say an argument"는 어색해요. 논거를 제시할 때는 put forward를 써요.', 'She put forward a compelling argument for changing the policy.', '그녀는 정책 변경을 위한 설득력 있는 주장을 내놓았어요.', 'The professor put forward several arguments to support his theory.', '교수는 자신의 이론을 뒷받침하기 위해 여러 주장을 내놓았어요.', 'B2', 'discussion', 2, 'argument debate discussion point', 3),
('col_discussion_04', 'take', 'a stance', 'take a stance', '입장을 취하다', 'have', '"have a stance"도 쓰이지만 take a stance는 의도적인 선택을 강조해요.', 'The company took a clear stance on environmental issues.', '그 회사는 환경 문제에 대해 명확한 입장을 취했어요.', 'It''s important to take a stance and defend it with evidence.', '입장을 취하고 그것을 증거로 뒷받침하는 것이 중요해요.', 'B2', 'discussion', 2, 'stance opinion position discussion debate', 4),
('col_discussion_05', 'challenge', 'an assumption', 'challenge an assumption', '가정에 의문을 제기하다', 'question', '"question an assumption"도 맞지만 challenge는 더 직접적인 반박을 강조해요.', 'He challenged the assumption that everyone agrees with the new system.', '그는 모든 사람이 새로운 시스템에 동의한다는 가정에 의문을 제기했어요.', 'Good critical thinkers are willing to challenge their own assumptions.', '좋은 비판적 사고자들은 자신의 가정에도 기꺼이 의문을 제기해요.', 'C1', 'discussion', 3, 'challenge assumption critical thinking debate', 5),
('col_discussion_06', 'back up', 'a claim', 'back up a claim', '주장을 뒷받침하다', 'prove', '"prove a claim"도 맞지만 back up은 증거나 논거로 지지하는 뉘앙스예요.', 'You need to back up your claim with solid data.', '주장을 탄탄한 데이터로 뒷받침해야 해요.', 'She backed up her claim with research from three different studies.', '그녀는 세 가지 다른 연구의 결과로 자신의 주장을 뒷받침했어요.', 'B2', 'discussion', 2, 'evidence claim support data proof', 6),
('col_discussion_07', 'hold', 'a debate', 'hold a debate', '토론을 개최하다', 'make', '"make a debate"는 어색해요. 토론을 개최할 때는 hold를 써요.', 'The school held a debate on the topic of climate change.', '학교는 기후 변화 주제로 토론을 개최했어요.', 'We hold a monthly debate on current affairs.', '우리는 시사 문제에 대한 월례 토론을 개최해요.', 'B1', 'discussion', 1, 'debate school discussion audience event', 7),
('col_discussion_08', 'come to', 'a conclusion', 'come to a conclusion', '결론에 이르다', 'make', '"make a conclusion"은 학문적으로 어색해요. 결론에 도달할 때는 come to 또는 draw를 써요.', 'After reviewing the data, we came to a clear conclusion.', '데이터를 검토한 후 우리는 명확한 결론에 이르렀어요.', 'It took weeks of discussion before they could come to a conclusion.', '결론에 이르는 데 수 주간의 토론이 필요했어요.', 'B1', 'discussion', 1, 'conclusion decision discussion result meeting', 8),
('col_discussion_09', 'express', 'an opinion', 'express an opinion', '의견을 표현하다', 'say', '"say an opinion"은 어색해요. 의견을 말할 때는 express 또는 share를 써요.', 'Everyone was encouraged to express their opinion freely.', '모든 사람이 자유롭게 의견을 표현하도록 장려됐어요.', 'She expressed her opinion clearly without being aggressive.', '그녀는 공격적이지 않게 자신의 의견을 명확하게 표현했어요.', 'B1', 'discussion', 1, 'opinion expression discussion talking', 9),
('col_discussion_10', 'acknowledge', 'a viewpoint', 'acknowledge a viewpoint', '관점을 인정하다', 'accept', '"accept a viewpoint"도 맞지만 acknowledge는 완전히 동의하지 않아도 인정하는 뉘앙스예요.', 'A good debater always acknowledges the opposing viewpoint.', '좋은 토론자는 항상 반대 관점을 인정해요.', 'She acknowledged his viewpoint before explaining why she disagreed.', '그녀는 반박하기 전에 그의 관점을 인정했어요.', 'C1', 'discussion', 3, 'viewpoint acknowledge discussion respect', 10),
('col_discussion_11', 'make', 'a point', 'make a point', '요점을 말하다', 'do', '"do a point"는 틀린 표현이에요. 요점을 전달할 때는 make를 써요.', 'He made a very good point about the importance of communication.', '그는 소통의 중요성에 대해 매우 좋은 요점을 말했어요.', 'I''d like to make a point before we move on.', '계속 진행하기 전에 요점을 말하고 싶어요.', 'B1', 'discussion', 1, 'point discussion meeting argument', 11),
('col_discussion_12', 'open up', 'a discussion', 'open up a discussion', '토론을 시작하다', 'start', '"start a discussion"도 맞지만 open up은 더 넓은 참여를 유도하는 뉘앙스예요.', 'The moderator opened up a discussion on workplace diversity.', '사회자는 직장 다양성에 대한 토론을 시작했어요.', 'The documentary opened up a wider public discussion on the issue.', '그 다큐멘터리는 그 문제에 대해 더 넓은 공개 토론을 시작했어요.', 'B2', 'discussion', 2, 'discussion open dialogue group panel', 12),
('col_discussion_13', 'disagree', 'with', 'disagree with', '~에 동의하지 않다', 'oppose', '"oppose"도 맞지만 disagree with가 더 일상적이고 부드러운 반대예요.', 'I respect your view, but I disagree with your conclusion.', '당신의 견해를 존중하지만 결론에는 동의하지 않아요.', 'She politely disagreed with the proposal during the meeting.', '그녀는 회의에서 정중하게 제안에 동의하지 않았어요.', 'B1', 'discussion', 1, 'disagree debate discussion opinion', 13),
('col_discussion_14', 'build on', 'an idea', 'build on an idea', '아이디어를 발전시키다', 'develop', '"develop an idea"도 맞지만 build on은 기존 아이디어를 기반으로 발전시키는 뉘앙스예요.', 'Let''s build on that idea and explore it further.', '그 아이디어를 발전시켜 더 깊이 탐구해 봐요.', 'She built on her colleague''s suggestion to create a new proposal.', '그녀는 동료의 제안을 발전시켜 새로운 제안서를 만들었어요.', 'B2', 'discussion', 2, 'idea develop build discussion creative', 14),
('col_discussion_15', 'summarise', 'the key points', 'summarise the key points', '핵심 요점을 요약하다', 'explain', '"explain the key points"도 맞지만 summarise는 간결하게 정리하는 것을 강조해요.', 'At the end of the meeting, she summarised the key points discussed.', '회의 말미에 그녀는 논의된 핵심 요점을 요약했어요.', 'Could you summarise the key points in one paragraph?', '핵심 요점을 한 단락으로 요약해 줄 수 있어요?', 'B2', 'discussion', 2, 'summary key points meeting discussion notes', 15),
('col_discussion_16', 'draw', 'a distinction', 'draw a distinction', '구분하다, 차이를 명확히 하다', 'make', '"make a distinction"도 맞지만 draw a distinction은 논거에서 더 학문적으로 쓰여요.', 'We need to draw a distinction between fact and opinion.', '사실과 의견을 구분할 필요가 있어요.', 'The speaker drew a clear distinction between the two concepts.', '연사는 두 개념 사이의 명확한 구분을 지었어요.', 'C1', 'discussion', 3, 'distinction difference concept debate analysis', 16),
('col_discussion_17', 'shift', 'the focus', 'shift the focus', '초점을 바꾸다', 'change', '"change the focus"도 맞지만 shift는 점진적인 변화를 강조해요.', 'The moderator shifted the focus to the economic aspects.', '사회자는 경제적 측면으로 초점을 바꿨어요.', 'He tried to shift the focus away from the controversial point.', '그는 논란이 되는 요점에서 초점을 바꾸려 했어요.', 'C1', 'discussion', 3, 'focus discussion shift change topic', 17),
('col_discussion_18', 'reach', 'an impasse', 'reach an impasse', '교착 상태에 빠지다', 'get', '"get stuck"도 맞지만 reach an impasse는 협상이나 토론에서 더 격식 있는 표현이에요.', 'The negotiations reached an impasse after three days.', '협상은 3일 후 교착 상태에 빠졌어요.', 'Discussions reached an impasse when neither side would compromise.', '어느 쪽도 타협하지 않으려 하자 토론이 교착 상태에 빠졌어요.', 'C1', 'discussion', 3, 'impasse stuck negotiation discussion deadlock', 18),
('col_discussion_19', 'invite', 'feedback', 'invite feedback', '피드백을 요청하다', 'ask', '"ask for feedback"도 맞지만 invite feedback은 더 개방적이고 따뜻한 뉘앙스예요.', 'At the end of her presentation, she invited feedback from the audience.', '발표 마지막에 그녀는 청중에게 피드백을 요청했어요.', 'The manager invited feedback from the whole team about the new process.', '관리자는 새 프로세스에 대해 팀 전체에게 피드백을 요청했어요.', 'B2', 'discussion', 2, 'feedback discussion invite team comment', 19),
('col_discussion_20', 'wrap up', 'a discussion', 'wrap up a discussion', '토론을 마무리하다', 'end', '"end a discussion"도 맞지만 wrap up은 요약하며 마무리하는 뉘앙스예요.', 'Let''s wrap up the discussion and agree on next steps.', '토론을 마무리하고 다음 단계에 합의해요.', 'She wrapped up the discussion by thanking everyone for their input.', '그녀는 모든 사람의 의견에 감사하며 토론을 마무리했어요.', 'B2', 'discussion', 2, 'wrap up discussion close meeting end', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_presentation_01', 'give', 'a presentation', 'give a presentation', '발표를 하다', 'make', '"make a presentation"도 쓰이지만 give a presentation이 훨씬 더 자연스러워요.', 'She gave an impressive presentation to the board of directors.', '그녀는 이사회에 인상적인 발표를 했어요.', 'He gives a presentation every Monday morning to update the team.', '그는 팀 업데이트를 위해 매주 월요일 아침 발표를 해요.', 'B1', 'presentation', 1, 'presentation business meeting speaker slides', 1),
('col_presentation_02', 'deliver', 'a speech', 'deliver a speech', '연설을 하다', 'say', '"say a speech"는 틀린 표현이에요. 연설을 할 때는 give 또는 deliver를 써요.', 'The CEO delivered a powerful speech at the annual conference.', '최고경영자는 연례 회의에서 강력한 연설을 했어요.', 'He delivered a speech that moved the entire audience to tears.', '그는 청중 전체를 눈물 짓게 만드는 연설을 했어요.', 'B2', 'presentation', 2, 'speech delivery conference speaker audience', 2),
('col_presentation_03', 'set up', 'a slide deck', 'set up a slide deck', '슬라이드 덱을 준비하다', 'make', '"make slides"도 맞지만 set up a slide deck은 준비를 포함한 더 격식 있는 표현이에요.', 'She spent the morning setting up her slide deck for the afternoon presentation.', '그녀는 오후 발표를 위해 오전에 슬라이드 덱을 준비했어요.', 'Can you set up the slide deck before the clients arrive?', '고객이 도착하기 전에 슬라이드 덱을 준비해 줄 수 있어요?', 'B1', 'presentation', 1, 'slides presentation setup technology screen', 3),
('col_presentation_04', 'walk through', 'the data', 'walk through the data', '데이터를 설명하다', 'explain', '"explain the data"도 맞지만 walk through는 단계별로 안내하는 뉘앙스예요.', 'Let me walk you through the data from last quarter.', '지난 분기 데이터를 단계별로 설명해 드릴게요.', 'She walked through the research findings one slide at a time.', '그녀는 연구 결과를 슬라이드 하나씩 설명했어요.', 'B2', 'presentation', 2, 'data explanation walkthrough slides chart', 4),
('col_presentation_05', 'capture', 'attention', 'capture attention', '주의를 끌다', 'get', '"get attention"도 맞지만 capture는 단번에 강하게 끌어들이는 뉘앙스예요.', 'A strong opening sentence captures the audience''s attention immediately.', '강한 첫 문장은 즉각적으로 청중의 주의를 끌어요.', 'Use a surprising statistic to capture attention at the start.', '시작할 때 놀라운 통계를 사용해서 주의를 끄세요.', 'B2', 'presentation', 2, 'attention audience speaker engagement', 5),
('col_presentation_06', 'outline', 'the agenda', 'outline the agenda', '안건을 개요로 설명하다', 'say', '"say the agenda"는 어색해요. 안건을 설명할 때는 outline 또는 go through를 써요.', 'She outlined the agenda at the beginning of the presentation.', '그녀는 발표 시작 부분에 안건을 개요로 설명했어요.', 'Please outline the agenda so everyone knows what to expect.', '모든 사람이 무엇을 기대해야 할지 알도록 안건을 설명해 주세요.', 'B1', 'presentation', 1, 'agenda outline meeting schedule presentation', 6),
('col_presentation_07', 'make', 'eye contact', 'make eye contact', '눈을 마주치다', 'do', '"do eye contact"는 틀린 표현이에요. 눈을 마주칠 때는 make eye contact를 써요.', 'Making eye contact with the audience builds trust and confidence.', '청중과 눈을 마주치는 것은 신뢰와 자신감을 형성해요.', 'She made eye contact with different members of the audience throughout her talk.', '그녀는 발표 내내 청중의 다양한 구성원과 눈을 마주쳤어요.', 'B1', 'presentation', 1, 'eye contact speaker audience engagement', 7),
('col_presentation_08', 'engage', 'the audience', 'engage the audience', '청중을 사로잡다', 'entertain', '"entertain the audience"도 맞지만 engage는 더 능동적인 참여를 강조해요.', 'Good presenters know how to engage the audience from start to finish.', '좋은 발표자는 처음부터 끝까지 청중을 사로잡는 방법을 알아요.', 'He used interactive questions to engage the audience.', '그는 상호작용 질문으로 청중을 사로잡았어요.', 'B2', 'presentation', 2, 'audience engagement speaker interactive presentation', 8),
('col_presentation_09', 'highlight', 'key findings', 'highlight key findings', '핵심 결과를 강조하다', 'show', '"show key findings"도 맞지만 highlight는 특별히 부각시키는 뉘앙스예요.', 'The presenter highlighted the key findings from the customer survey.', '발표자는 고객 설문 조사의 핵심 결과를 강조했어요.', 'Be sure to highlight key findings in bold on your slides.', '슬라이드에서 핵심 결과를 굵게 강조하세요.', 'B2', 'presentation', 2, 'findings highlight research data slide', 9),
('col_presentation_10', 'field', 'questions', 'field questions', '질문을 처리하다', 'answer', '"answer questions"도 맞지만 field는 다양한 질문들을 능숙하게 처리하는 뉘앙스예요.', 'After the talk, he fielded questions from the audience for 20 minutes.', '발표 후 그는 20분 동안 청중의 질문을 처리했어요.', 'She was well prepared to field any questions about the budget.', '그녀는 예산에 관한 어떤 질문도 처리할 준비가 되어 있었어요.', 'C1', 'presentation', 3, 'questions audience Q&A presentation field', 10),
('col_presentation_11', 'wrap up', 'a presentation', 'wrap up a presentation', '발표를 마무리하다', 'finish', '"finish a presentation"도 맞지만 wrap up은 요약과 함께 마무리하는 뉘앙스예요.', 'She wrapped up her presentation with a memorable call to action.', '그녀는 기억에 남는 행동 촉구와 함께 발표를 마무리했어요.', 'Let''s wrap up the presentation in the next five minutes.', '앞으로 5분 안에 발표를 마무리해요.', 'B2', 'presentation', 2, 'wrap up conclusion presentation end close', 11),
('col_presentation_12', 'refer', 'to a chart', 'refer to a chart', '차트를 언급하다', 'show', '"show a chart"도 맞지만 refer to는 발표 중에 차트를 가리키며 언급하는 뉘앙스예요.', 'She referred to the chart on the left to support her argument.', '그녀는 왼쪽 차트를 언급하며 자신의 주장을 뒷받침했어요.', 'If you refer to the chart on slide 5, you can see a clear trend.', '슬라이드 5의 차트를 보시면 명확한 추세를 볼 수 있어요.', 'B1', 'presentation', 1, 'chart slide data refer presentation', 12),
('col_presentation_13', 'take', 'questions', 'take questions', '질문을 받다', 'get', '"get questions"도 쓰이지만 take questions는 질문을 받겠다는 공식적인 선언이에요.', 'I''ll take questions at the end of the presentation.', '발표 마지막에 질문을 받을게요.', 'She took questions from the panel after her keynote speech.', '그녀는 기조연설 후 패널의 질문을 받았어요.', 'B1', 'presentation', 1, 'questions audience speaker Q&A', 13),
('col_presentation_14', 'lose', 'the thread', 'lose the thread', '발표 흐름을 잃다', 'forget', '"forget what to say"도 맞지만 lose the thread는 발표 흐름이 끊기는 것을 강조해요.', 'He lost the thread halfway through and had to check his notes.', '그는 중간에 흐름을 잃어 메모를 확인해야 했어요.', 'Don''t lose the thread by including too many unnecessary details.', '불필요한 세부 사항을 너무 많이 포함해서 흐름을 잃지 마세요.', 'C1', 'presentation', 3, 'presentation focus flow thread clarity', 14),
('col_presentation_15', 'handle', 'nerves', 'handle nerves', '긴장을 다스리다', 'control', '"control nerves"도 맞지만 handle nerves는 실질적으로 관리하는 뉘앙스예요.', 'She learned techniques to handle nerves before important presentations.', '그녀는 중요한 발표 전에 긴장을 다스리는 기법을 배웠어요.', 'Deep breathing can help you handle nerves before going on stage.', '심호흡은 무대에 오르기 전에 긴장을 다스리는 데 도움이 돼요.', 'B2', 'presentation', 2, 'nerves anxiety stage presentation manage', 15),
('col_presentation_16', 'illustrate', 'a point', 'illustrate a point', '요점을 설명하다', 'show', '"show a point"는 어색해요. 예시를 들어 요점을 설명할 때는 illustrate를 써요.', 'She used a real-life example to illustrate her point.', '그녀는 실생활 예시를 사용해서 요점을 설명했어요.', 'He illustrated his point with a short video clip.', '그는 짧은 영상 클립으로 요점을 설명했어요.', 'B2', 'presentation', 2, 'illustration example point presentation explain', 16),
('col_presentation_17', 'run', 'over time', 'run over time', '시간을 초과하다', 'exceed', '"exceed the time"도 맞지만 run over time은 일상적인 발표 상황에서 더 자연스러워요.', 'The presentation ran over time because there were so many questions.', '질문이 너무 많아서 발표가 시간을 초과했어요.', 'Try not to run over time — keep an eye on the clock.', '시간을 초과하지 않도록 시계를 확인하세요.', 'B2', 'presentation', 2, 'time presentation over schedule clock', 17),
('col_presentation_18', 'transition', 'smoothly', 'transition smoothly', '매끄럽게 전환하다', 'move', '"move to the next slide"도 맞지만 transition smoothly는 발표 흐름의 자연스러움을 강조해요.', 'A good presenter transitions smoothly between sections.', '좋은 발표자는 섹션 간에 매끄럽게 전환해요.', 'Practice transitioning smoothly so the audience follows along easily.', '청중이 쉽게 따라올 수 있도록 매끄럽게 전환하는 연습을 하세요.', 'C1', 'presentation', 3, 'transition flow presentation smooth section', 18),
('col_presentation_19', 'tailor', 'a message', 'tailor a message', '메시지를 맞춤화하다', 'change', '"change the message"도 맞지만 tailor는 특정 청중에 맞게 조정하는 뉘앙스예요.', 'You should tailor your message to the specific needs of your audience.', '청중의 특정 니즈에 맞게 메시지를 맞춤화해야 해요.', 'She tailored her message differently for each department she presented to.', '그녀는 발표한 각 부서에 맞게 메시지를 다르게 맞춤화했어요.', 'C1', 'presentation', 3, 'message audience tailor communication', 19),
('col_presentation_20', 'pause', 'for effect', 'pause for effect', '효과를 위해 잠시 멈추다', 'stop', '"stop"도 맞지만 pause for effect는 의도적인 극적 멈춤을 강조해요.', 'She paused for effect before revealing the final results.', '그녀는 최종 결과를 발표하기 전에 효과를 위해 잠시 멈췄어요.', 'Great speakers know when to pause for effect to let key points sink in.', '훌륭한 연사들은 핵심 요점이 스며들도록 언제 멈춰야 할지 알아요.', 'C1', 'presentation', 3, 'pause effect speech delivery timing', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_negotiation_01', 'reach', 'an agreement', 'reach an agreement', '합의에 도달하다', 'make', '"make an agreement"도 쓰이지만 reach는 양측이 노력 끝에 도달하는 뉘앙스예요.', 'After long negotiations, both sides reached an agreement.', '오랜 협상 끝에 양측은 합의에 도달했어요.', 'We hope to reach an agreement before the end of the month.', '이달 말 전에 합의에 도달하기를 바라요.', 'B1', 'negotiation', 1, 'agreement handshake deal business negotiation', 1),
('col_negotiation_02', 'make', 'a concession', 'make a concession', '양보하다', 'do', '"do a concession"은 틀린 표현이에요. 양보할 때는 make a concession을 써요.', 'Both sides had to make concessions to reach the final deal.', '양측은 최종 합의에 이르기 위해 양보해야 했어요.', 'She made a small concession on the price to close the deal quickly.', '그녀는 거래를 빨리 성사시키기 위해 가격에 대해 약간 양보했어요.', 'B2', 'negotiation', 2, 'concession deal negotiation business compromise', 2),
('col_negotiation_03', 'strike', 'a deal', 'strike a deal', '거래를 성사시키다', 'make', '"make a deal"도 맞지만 strike a deal은 더 극적이고 결정적인 순간을 강조해요.', 'The two companies struck a deal worth 50 million dollars.', '두 회사는 5000만 달러 규모의 거래를 성사시켰어요.', 'He struck a deal with the supplier after weeks of back-and-forth.', '그는 수 주간의 협상 끝에 공급업체와 거래를 성사시켰어요.', 'B2', 'negotiation', 2, 'deal business agreement contract strike', 3),
('col_negotiation_04', 'walk away', 'from the table', 'walk away from the table', '협상 테이블을 떠나다', 'leave', '"leave the table"도 맞지만 walk away from the table은 협상 결렬을 더 강하게 표현해요.', 'If the offer isn''t improved, we will walk away from the table.', '제안이 개선되지 않으면 우리는 협상 테이블을 떠날 거예요.', 'She walked away from the table when they refused her key demand.', '그들이 핵심 요구를 거부하자 그녀는 협상 테이블을 떠났어요.', 'B2', 'negotiation', 2, 'walk away negotiation deal table', 4),
('col_negotiation_05', 'drive', 'a hard bargain', 'drive a hard bargain', '강하게 협상하다', 'make', '"make a hard bargain"은 어색해요. 강경하게 협상할 때는 drive a hard bargain을 써요.', 'He''s known for driving a hard bargain in contract negotiations.', '그는 계약 협상에서 강하게 협상하는 것으로 알려져 있어요.', 'She drives a hard bargain but always keeps her word.', '그녀는 강하게 협상하지만 항상 약속을 지켜요.', 'C1', 'negotiation', 3, 'bargain negotiation strong deal hard', 5),
('col_negotiation_06', 'come to', 'the table', 'come to the table', '협상 테이블에 나서다', 'join', '"join the negotiation"도 맞지만 come to the table은 협상 참여 의사를 나타내는 표현이에요.', 'Both parties need to come to the table with an open mind.', '양측은 열린 마음으로 협상 테이블에 나서야 해요.', 'The union agreed to come to the table after the management made new offers.', '경영진이 새로운 제안을 내놓자 노조는 협상 테이블에 나서기로 합의했어요.', 'C1', 'negotiation', 3, 'table negotiation meeting deal', 6),
('col_negotiation_07', 'set', 'terms', 'set terms', '조건을 정하다', 'make', '"make terms"는 어색해요. 협상 조건을 정할 때는 set terms를 써요.', 'Before signing, you should clearly set the terms of the agreement.', '서명하기 전에 합의 조건을 명확하게 정해야 해요.', 'The landlord set strict terms for the lease renewal.', '집주인은 임대 갱신에 대한 엄격한 조건을 정했어요.', 'B2', 'negotiation', 2, 'terms conditions agreement contract legal', 7),
('col_negotiation_08', 'bridge', 'a gap', 'bridge a gap', '격차를 좁히다', 'close', '"close a gap"도 맞지만 bridge a gap은 양측의 차이를 잇는 뉘앙스예요.', 'The mediator helped bridge the gap between the two sides.', '중재자는 양측의 격차를 좁히는 데 도움을 줬어요.', 'We need to bridge the gap in salary expectations before we proceed.', '진행하기 전에 급여 기대치의 격차를 좁혀야 해요.', 'C1', 'negotiation', 3, 'gap bridge difference negotiation compromise', 8),
('col_negotiation_09', 'put', 'on the table', 'put something on the table', '제안을 내놓다', 'say', '"say an offer"는 어색해요. 제안을 공식적으로 내놓을 때는 put on the table을 써요.', 'What can you put on the table to make this deal work?', '이 거래를 성사시키기 위해 어떤 제안을 내놓을 수 있어요?', 'They put a generous severance package on the table to end the dispute.', '그들은 분쟁을 종식시키기 위해 넉넉한 퇴직금 패키지를 제안으로 내놓았어요.', 'B2', 'negotiation', 2, 'offer proposal table negotiation deal', 9),
('col_negotiation_10', 'hold', 'firm', 'hold firm', '입장을 굳건히 유지하다', 'stay', '"stay firm"도 맞지만 hold firm은 압박에도 흔들리지 않는다는 뉘앙스예요.', 'Despite the pressure, she held firm on her original offer.', '압박에도 불구하고 그녀는 원래 제안에 입장을 굳건히 유지했어요.', 'The union held firm on its demand for a 10% pay rise.', '노조는 10% 임금 인상 요구에 대해 입장을 굳건히 유지했어요.', 'B2', 'negotiation', 2, 'firm hold position negotiation pressure', 10),
('col_negotiation_11', 'draw up', 'a contract', 'draw up a contract', '계약서를 작성하다', 'make', '"make a contract"도 쓰이지만 draw up은 공식 문서를 법적으로 작성하는 뉘앙스예요.', 'The lawyer drew up a contract for both parties to sign.', '변호사는 양측이 서명할 계약서를 작성했어요.', 'We''ll draw up a contract once we''ve agreed on all the terms.', '모든 조건에 합의하면 계약서를 작성할게요.', 'B2', 'negotiation', 2, 'contract legal document business agreement', 11),
('col_negotiation_12', 'meet', 'in the middle', 'meet in the middle', '절충점을 찾다', 'compromise', '"compromise"도 맞지만 meet in the middle은 양측이 동등하게 양보하는 뉘앙스예요.', 'They met in the middle on price, and the deal was closed.', '그들은 가격에서 절충점을 찾았고 거래가 성사됐어요.', 'If you can meet in the middle, we can move forward today.', '절충점을 찾을 수 있다면 오늘 바로 진행할 수 있어요.', 'B1', 'negotiation', 1, 'compromise middle meet deal negotiation', 12),
('col_negotiation_13', 'reject', 'an offer', 'reject an offer', '제안을 거절하다', 'refuse', '"refuse an offer"도 맞지만 reject는 더 공식적인 거절을 강조해요.', 'She rejected the first offer and proposed a counter-offer.', '그녀는 첫 번째 제안을 거절하고 반대 제안을 했어요.', 'The board rejected the offer due to concerns about long-term viability.', '이사회는 장기적인 실행 가능성에 대한 우려로 제안을 거절했어요.', 'B1', 'negotiation', 1, 'rejection offer deal negotiation refuse', 13),
('col_negotiation_14', 'push', 'for better terms', 'push for better terms', '더 나은 조건을 요구하다', 'ask', '"ask for better terms"도 맞지만 push는 더 강하게 요구한다는 뉘앙스예요.', 'The employee pushed for better terms before agreeing to the contract.', '직원은 계약에 동의하기 전에 더 나은 조건을 강하게 요구했어요.', 'You have more leverage than you think — push for better terms.', '생각보다 협상력이 있어요. 더 나은 조건을 요구해 보세요.', 'C1', 'negotiation', 3, 'terms negotiation push demand better', 14),
('col_negotiation_15', 'sign', 'a contract', 'sign a contract', '계약서에 서명하다', 'write', '"write a contract"는 작성하는 것이고 sign은 서명하는 것이에요. 혼동하지 마세요.', 'Both parties signed the contract and shook hands.', '양측은 계약서에 서명하고 악수를 나눴어요.', 'She refused to sign the contract until all the changes were made.', '그녀는 모든 변경 사항이 이루어질 때까지 계약서에 서명하기를 거부했어요.', 'B1', 'negotiation', 1, 'contract sign agreement legal business', 15),
('col_negotiation_16', 'negotiate', 'a price', 'negotiate a price', '가격을 협상하다', 'discuss', '"discuss a price"도 맞지만 negotiate는 서로 다른 입장에서 조율하는 뉘앙스예요.', 'In many countries, it''s normal to negotiate the price at a market.', '많은 나라에서 시장에서 가격을 협상하는 것이 일반적이에요.', 'She was able to negotiate a lower price for the property.', '그녀는 부동산의 더 낮은 가격을 협상할 수 있었어요.', 'B1', 'negotiation', 1, 'price negotiation deal business market', 16),
('col_negotiation_17', 'break down', 'negotiations', 'break down in negotiations', '협상이 결렬되다', 'fail', '"fail in negotiations"도 맞지만 break down은 협상이 갑자기 결렬되는 뉘앙스예요.', 'Negotiations broke down after a key disagreement on delivery terms.', '납기 조건에 대한 핵심적인 이견 이후 협상이 결렬됐어요.', 'If talks break down, we will need to find another solution.', '협상이 결렬되면 다른 해결책을 찾아야 해요.', 'B2', 'negotiation', 2, 'breakdown negotiation failure deal talks', 17),
('col_negotiation_18', 'table', 'a proposal', 'table a proposal', '제안을 제출하다', 'bring', '"bring a proposal"도 맞지만 table a proposal은 공식적인 안건 제출을 강조해요.', 'The union tabled a proposal for a four-day work week.', '노조는 주 4일 근무제에 대한 제안을 제출했어요.', 'We''d like to table a proposal before the meeting ends.', '회의가 끝나기 전에 제안을 제출하고 싶어요.', 'C1', 'negotiation', 3, 'proposal table submission meeting official', 18),
('col_negotiation_19', 'finalize', 'an agreement', 'finalize an agreement', '합의를 최종 확정하다', 'finish', '"finish an agreement"는 어색해요. 합의를 최종 확정할 때는 finalize를 써요.', 'Both teams worked late to finalize the agreement before the deadline.', '양 팀은 마감 기한 전에 합의를 최종 확정하기 위해 늦게까지 일했어요.', 'We expect to finalize the agreement by the end of the week.', '이번 주말까지 합의를 최종 확정할 것으로 기대해요.', 'B2', 'negotiation', 2, 'agreement finalize deal close contract', 19),
('col_negotiation_20', 'leverage', 'a position', 'leverage a position', '유리한 위치를 활용하다', 'use', '"use a position"도 맞지만 leverage는 전략적으로 강점을 활용하는 뉘앙스예요.', 'They leveraged their market position to negotiate better prices.', '그들은 더 나은 가격을 협상하기 위해 시장 지위를 활용했어요.', 'She leveraged her expertise to secure a favorable contract.', '그녀는 유리한 계약을 따내기 위해 전문성을 활용했어요.', 'C1', 'negotiation', 3, 'leverage position strength negotiation strategy', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_humanities_01', 'draw', 'a conclusion', 'draw a conclusion', '결론을 도출하다', 'make', '"make a conclusion"은 어색해요. 논리적 추론으로 결론을 낼 때는 draw를 써요.', 'From the evidence, we can draw a conclusion about the author''s intent.', '증거로부터 작가의 의도에 대한 결론을 도출할 수 있어요.', 'Historians draw conclusions by carefully examining primary sources.', '역사가들은 1차 자료를 주의 깊게 검토하여 결론을 도출해요.', 'B2', 'humanities', 2, 'conclusion research analysis study humanities', 1),
('col_humanities_02', 'trace', 'the origins', 'trace the origins', '기원을 추적하다', 'find', '"find the origins"도 맞지만 trace는 역사적 경로를 따라가는 뉘앙스예요.', 'Scholars have traced the origins of the English language to Anglo-Saxon.', '학자들은 영어의 기원을 앵글로색슨어까지 추적해 왔어요.', 'It''s fascinating to trace the origins of common words and phrases.', '일반적인 단어와 구절의 기원을 추적하는 것은 흥미로워요.', 'B2', 'humanities', 2, 'origins history trace etymology culture', 2),
('col_humanities_03', 'conduct', 'research', 'conduct research', '연구를 수행하다', 'do', '"do research"도 맞지만 conduct research는 더 격식 있고 체계적인 연구를 강조해요.', 'She conducted extensive research into medieval literature.', '그녀는 중세 문학에 대해 광범위한 연구를 수행했어요.', 'The university is conducting research on the effects of social media on language.', '대학은 소셜 미디어가 언어에 미치는 영향에 대한 연구를 수행하고 있어요.', 'B2', 'humanities', 2, 'research academic university library study', 3),
('col_humanities_04', 'interpret', 'a text', 'interpret a text', '텍스트를 해석하다', 'read', '"read a text"는 단순히 읽는 것이고 interpret는 의미를 분석하고 해석하는 것이에요.', 'Students are asked to interpret the text from a feminist perspective.', '학생들은 페미니스트 관점에서 텍스트를 해석하도록 요청받아요.', 'How you interpret a text depends heavily on your cultural background.', '텍스트를 어떻게 해석하는지는 문화적 배경에 크게 좌우돼요.', 'B2', 'humanities', 2, 'text interpretation literature analysis reading', 4),
('col_humanities_05', 'challenge', 'a theory', 'challenge a theory', '이론에 의문을 제기하다', 'question', '"question a theory"도 맞지만 challenge는 더 적극적인 반박을 강조해요.', 'New archaeological findings challenge the established theory about ancient migration.', '새로운 고고학적 발견은 고대 이주에 대한 기존 이론에 의문을 제기해요.', 'The essay challenges the theory that art reflects society passively.', '그 에세이는 예술이 사회를 수동적으로 반영한다는 이론에 의문을 제기해요.', 'C1', 'humanities', 3, 'theory challenge critique academic debate', 5),
('col_humanities_06', 'shed light on', 'history', 'shed light on history', '역사에 빛을 비추다, 역사를 밝히다', 'explain', '"explain history"도 맞지만 shed light on은 새로운 이해나 통찰을 제공하는 뉘앙스예요.', 'New documents shed light on a period of history that was previously misunderstood.', '새로운 문서들이 이전에 잘못 이해됐던 역사적 시기를 밝혀줬어요.', 'The research sheds light on how ancient societies dealt with climate change.', '그 연구는 고대 사회가 기후 변화에 어떻게 대처했는지를 밝혀줘요.', 'C1', 'humanities', 3, 'history revelation research light understanding', 6),
('col_humanities_07', 'analyse', 'a text', 'analyse a text', '텍스트를 분석하다', 'study', '"study a text"도 맞지만 analyse는 더 비판적이고 체계적인 분석을 강조해요.', 'The class was asked to analyse the text using literary theory.', '수업에서 문학 이론을 사용하여 텍스트를 분석하도록 요청받았어요.', 'She analysed the text to identify recurring themes and motifs.', '그녀는 반복되는 주제와 모티프를 찾아내기 위해 텍스트를 분석했어요.', 'B2', 'humanities', 2, 'analysis text literary critical study', 7),
('col_humanities_08', 'preserve', 'a manuscript', 'preserve a manuscript', '원고를 보존하다', 'keep', '"keep a manuscript"는 어색해요. 원고와 같은 문화유산을 보존할 때는 preserve를 써요.', 'The library works to preserve ancient manuscripts from deterioration.', '도서관은 고대 원고가 손상되지 않도록 보존하기 위해 노력해요.', 'Digitizing books is a modern way to preserve important manuscripts.', '책을 디지털화하는 것은 중요한 원고를 보존하는 현대적인 방법이에요.', 'B1', 'humanities', 1, 'manuscript library archive preservation history', 8),
('col_humanities_09', 'cite', 'a source', 'cite a source', '출처를 인용하다', 'use', '"use a source"도 맞지만 cite는 공식적으로 출처를 명시하는 것을 강조해요.', 'Always cite your sources when writing an academic essay.', '학술 에세이를 작성할 때는 항상 출처를 인용하세요.', 'She cited three primary sources to support her argument.', '그녀는 자신의 주장을 뒷받침하기 위해 세 가지 1차 출처를 인용했어요.', 'B1', 'humanities', 1, 'citation source reference academic essay', 9),
('col_humanities_10', 'examine', 'evidence', 'examine evidence', '증거를 검토하다', 'look at', '"look at evidence"도 쓰이지만 examine은 더 꼼꼼하고 체계적인 검토를 강조해요.', 'The historian examined the evidence before writing her conclusions.', '역사가는 결론을 쓰기 전에 증거를 검토했어요.', 'We need to examine all available evidence before making a judgment.', '판단을 내리기 전에 모든 가용 증거를 검토해야 해요.', 'B2', 'humanities', 2, 'evidence research examine analyze study', 10),
('col_humanities_11', 'explore', 'a theme', 'explore a theme', '주제를 탐구하다', 'find', '"find a theme"도 맞지만 explore는 주제를 깊이 탐구하는 뉘앙스예요.', 'The novel explores the theme of identity in modern society.', '그 소설은 현대 사회에서의 정체성이라는 주제를 탐구해요.', 'The lecture explored the theme of power in Shakespeare''s plays.', '강의는 셰익스피어 희곡에서 권력이라는 주제를 탐구했어요.', 'B2', 'humanities', 2, 'theme exploration literature analysis subject', 11),
('col_humanities_12', 'question', 'assumptions', 'question assumptions', '가정에 의문을 품다', 'doubt', '"doubt assumptions"도 맞지만 question은 건설적인 비판적 사고를 강조해요.', 'Great philosophers question the assumptions of their time.', '위대한 철학자들은 자신의 시대의 가정에 의문을 품어요.', 'The course encourages students to question their own cultural assumptions.', '그 과목은 학생들이 자신의 문화적 가정에 의문을 품도록 독려해요.', 'C1', 'humanities', 3, 'question assumption philosophy critical culture', 12),
('col_humanities_13', 'convey', 'meaning', 'convey meaning', '의미를 전달하다', 'show', '"show meaning"도 맞지만 convey는 의도적으로 의미를 전달하는 뉘앙스예요.', 'The painting conveys a deep sense of loss through its dark colour palette.', '그 그림은 어두운 색채 팔레트를 통해 깊은 상실감을 전달해요.', 'Language can convey subtle meanings that body language cannot.', '언어는 몸짓 언어가 전달하지 못하는 미묘한 의미를 전달할 수 있어요.', 'B2', 'humanities', 2, 'meaning convey communication language expression', 13),
('col_humanities_14', 'draw on', 'sources', 'draw on sources', '자료를 활용하다', 'use', '"use sources"도 맞지만 draw on은 다양한 출처에서 선택적으로 활용하는 뉘앙스예요.', 'The author drew on a wide range of historical sources to write the novel.', '저자는 소설을 쓰기 위해 다양한 역사적 자료를 활용했어요.', 'Good academic writing draws on both primary and secondary sources.', '좋은 학술 글쓰기는 1차 및 2차 자료를 모두 활용해요.', 'C1', 'humanities', 3, 'sources research draw academic reference', 14),
('col_humanities_15', 'make', 'an argument', 'make an argument', '주장을 펼치다', 'say', '"say an argument"는 어색해요. 논거를 제시하며 주장할 때는 make an argument를 써요.', 'The essay makes a compelling argument for the preservation of indigenous languages.', '그 에세이는 토착 언어 보존을 위한 설득력 있는 주장을 펼쳐요.', 'She made a strong argument during the seminar discussion.', '그녀는 세미나 토론에서 강력한 주장을 펼쳤어요.', 'B2', 'humanities', 2, 'argument essay academic debate humanities', 15),
('col_humanities_16', 'reflect on', 'the past', 'reflect on the past', '과거를 성찰하다', 'think about', '"think about the past"도 맞지만 reflect on은 더 깊은 사고와 통찰을 강조해요.', 'Historians reflect on the past to understand patterns in human behavior.', '역사가들은 인간 행동의 패턴을 이해하기 위해 과거를 성찰해요.', 'The memoir encourages readers to reflect on their own past experiences.', '그 회고록은 독자들이 자신의 과거 경험을 성찰하도록 이끌어요.', 'B2', 'humanities', 2, 'reflection past history memory thinking', 16),
('col_humanities_17', 'engage with', 'literature', 'engage with literature', '문학과 상호작용하다', 'read', '"read literature"도 맞지만 engage with는 단순히 읽는 것을 넘어 적극적으로 상호작용하는 것이에요.', 'Students are encouraged to actively engage with the literature, not just read it.', '학생들은 문학을 단순히 읽는 것을 넘어 적극적으로 상호작용하도록 독려받아요.', 'She engages with literature by asking questions and forming her own opinions.', '그녀는 질문하고 자신의 의견을 형성함으로써 문학과 상호작용해요.', 'C1', 'humanities', 3, 'literature engage reading critical thinking', 17),
('col_humanities_18', 'reshape', 'history', 'reshape history', '역사를 새롭게 쓰다', 'change', '"change history"도 맞지만 reshape는 역사의 이해나 방향을 바꾸는 뉘앙스예요.', 'New discoveries can reshape our understanding of ancient history.', '새로운 발견은 고대 역사에 대한 우리의 이해를 새롭게 쓸 수 있어요.', 'Social movements have the power to reshape history.', '사회 운동은 역사를 새롭게 쓸 힘을 가지고 있어요.', 'C1', 'humanities', 3, 'history reshape change society impact', 18),
('col_humanities_19', 'place', 'in context', 'place in context', '맥락 속에 위치시키다', 'explain', '"explain"도 맞지만 place in context는 더 넓은 배경 속에서 이해하는 뉘앙스예요.', 'To understand the poem, you need to place it in its historical context.', '시를 이해하려면 역사적 맥락 속에 위치시켜야 해요.', 'She placed the painting in the context of the Renaissance movement.', '그녀는 그 그림을 르네상스 운동의 맥락 속에 위치시켰어요.', 'B2', 'humanities', 2, 'context history culture setting interpretation', 19),
('col_humanities_20', 'raise', 'awareness', 'raise awareness', '인식을 높이다', 'increase', '"increase awareness"도 맞지만 raise awareness는 사람들의 주의를 끄는 더 자연스러운 표현이에요.', 'The humanities help raise awareness of diverse cultural perspectives.', '인문학은 다양한 문화적 관점에 대한 인식을 높이는 데 도움이 돼요.', 'The documentary raised awareness about the loss of endangered languages.', '그 다큐멘터리는 멸종 위기 언어의 소실에 대한 인식을 높였어요.', 'B1', 'humanities', 1, 'awareness culture education raise society', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_technology_01', 'develop', 'software', 'develop software', '소프트웨어를 개발하다', 'make', '"make software"도 쓰이지만 develop은 전문적인 개발 과정을 강조해요.', 'The team spent six months developing the new software platform.', '팀은 새로운 소프트웨어 플랫폼을 개발하는 데 6개월을 보냈어요.', 'She develops software for financial institutions around the world.', '그녀는 전 세계 금융 기관을 위한 소프트웨어를 개발해요.', 'B1', 'technology', 1, 'software development coding tech laptop', 1),
('col_technology_02', 'run', 'a program', 'run a program', '프로그램을 실행하다', 'open', '"open a program"도 맞지만 run은 프로그램이 실행되는 것을 강조해요.', 'You can run the program by double-clicking the icon.', '아이콘을 더블 클릭하면 프로그램을 실행할 수 있어요.', 'The server runs the program automatically every night at midnight.', '서버는 매일 밤 자정에 자동으로 프로그램을 실행해요.', 'B1', 'technology', 1, 'program computer run software execute', 2),
('col_technology_03', 'launch', 'an app', 'launch an app', '앱을 출시하다', 'make', '"make an app"은 앱을 만드는 것이에요. 공식적으로 출시할 때는 launch를 써요.', 'The startup launched its new app to great critical acclaim.', '그 스타트업은 큰 호평을 받으며 새 앱을 출시했어요.', 'They plan to launch the app in three new markets next year.', '그들은 내년에 세 개의 새 시장에서 앱을 출시할 계획이에요.', 'B1', 'technology', 1, 'app launch startup mobile release', 3),
('col_technology_04', 'store', 'data', 'store data', '데이터를 저장하다', 'save', '"save data"도 맞지만 store는 시스템이나 클라우드에 저장하는 더 기술적인 표현이에요.', 'The system stores all user data on secure cloud servers.', '시스템은 모든 사용자 데이터를 안전한 클라우드 서버에 저장해요.', 'Companies must be transparent about how they store personal data.', '기업은 개인 데이터를 어떻게 저장하는지 투명하게 공개해야 해요.', 'B1', 'technology', 1, 'data storage cloud server digital', 4),
('col_technology_05', 'process', 'data', 'process data', '데이터를 처리하다', 'analyse', '"analyse data"도 맞지만 process는 데이터를 변환하거나 처리하는 기계적 단계를 강조해요.', 'The algorithm can process millions of data points per second.', '알고리즘은 초당 수백만 개의 데이터 포인트를 처리할 수 있어요.', 'Modern computers process data far faster than those of twenty years ago.', '현대 컴퓨터는 20년 전보다 훨씬 빠르게 데이터를 처리해요.', 'B2', 'technology', 2, 'data process computing AI speed', 5),
('col_technology_06', 'update', 'software', 'update software', '소프트웨어를 업데이트하다', 'change', '"change software"는 다른 의미예요. 버전을 최신화할 때는 update를 써요.', 'Remember to update your software regularly to stay protected from threats.', '위협으로부터 보호받기 위해 소프트웨어를 정기적으로 업데이트하세요.', 'The company updated its software to fix a critical security vulnerability.', '회사는 심각한 보안 취약점을 수정하기 위해 소프트웨어를 업데이트했어요.', 'B1', 'technology', 1, 'software update security patch digital', 6),
('col_technology_07', 'breach', 'security', 'breach security', '보안을 침해하다', 'break', '"break security"도 쓰이지만 breach는 보안 맥락에서 더 전문적인 표현이에요.', 'Hackers breached the company''s security and stole customer data.', '해커들이 회사의 보안을 침해하고 고객 데이터를 훔쳤어요.', 'The system was designed to prevent anyone from breaching its security.', '그 시스템은 누구도 보안을 침해할 수 없도록 설계됐어요.', 'B2', 'technology', 2, 'security breach hacker cyber privacy', 7),
('col_technology_08', 'integrate', 'systems', 'integrate systems', '시스템을 통합하다', 'connect', '"connect systems"도 맞지만 integrate는 여러 시스템을 하나로 합치는 뉘앙스예요.', 'The project aims to integrate the company''s existing systems into one platform.', '그 프로젝트는 회사의 기존 시스템을 하나의 플랫폼으로 통합하는 것을 목표로 해요.', 'Integrating new software with legacy systems can be challenging.', '새 소프트웨어를 기존 시스템과 통합하는 것은 어려울 수 있어요.', 'B2', 'technology', 2, 'integration system platform technology connect', 8),
('col_technology_09', 'automate', 'a process', 'automate a process', '프로세스를 자동화하다', 'do automatically', '"do automatically"는 어색해요. 업무나 프로세스를 자동화할 때는 automate를 써요.', 'The company has automated its invoicing process to save time.', '회사는 시간을 절약하기 위해 청구서 발행 프로세스를 자동화했어요.', 'AI is increasingly used to automate repetitive tasks in the workplace.', '직장에서 반복적인 업무를 자동화하기 위해 AI가 점점 더 많이 사용되고 있어요.', 'B2', 'technology', 2, 'automation AI process technology efficiency', 9),
('col_technology_10', 'deploy', 'a solution', 'deploy a solution', '솔루션을 배포하다', 'use', '"use a solution"도 맞지만 deploy는 기술적 맥락에서 시스템을 가동하는 전문 표현이에요.', 'The IT team deployed the new solution across all departments.', 'IT 팀은 모든 부서에 새 솔루션을 배포했어요.', 'They plan to deploy the software update in three phases.', '그들은 3단계로 소프트웨어 업데이트를 배포할 계획이에요.', 'C1', 'technology', 3, 'deploy solution IT system rollout', 10),
('col_technology_11', 'troubleshoot', 'an issue', 'troubleshoot an issue', '문제를 해결하다', 'fix', '"fix an issue"도 맞지만 troubleshoot은 원인을 찾아 해결하는 과정을 강조해요.', 'The engineer spent three hours troubleshooting the network issue.', '엔지니어는 3시간 동안 네트워크 문제를 해결하는 데 시간을 보냈어요.', 'If you troubleshoot the issue before calling support, it often saves time.', '지원팀에 연락하기 전에 문제를 해결하려고 시도하면 시간을 절약할 수 있어요.', 'B2', 'technology', 2, 'troubleshoot issue fix error tech support', 11),
('col_technology_12', 'back up', 'data', 'back up data', '데이터를 백업하다', 'save', '"save data"도 맞지만 back up은 복사본을 만들어 보호하는 뉘앙스예요.', 'You should back up your data regularly in case of system failure.', '시스템 장애에 대비해 데이터를 정기적으로 백업해야 해요.', 'The IT department backs up all company data every 24 hours.', 'IT 부서는 24시간마다 모든 회사 데이터를 백업해요.', 'B1', 'technology', 1, 'backup data storage cloud recovery', 12),
('col_technology_13', 'encrypt', 'data', 'encrypt data', '데이터를 암호화하다', 'protect', '"protect data"도 맞지만 encrypt는 데이터를 암호화하는 특정 기술 방법을 강조해요.', 'All sensitive data is encrypted before being transmitted.', '모든 민감한 데이터는 전송 전에 암호화돼요.', 'You should encrypt your data to prevent unauthorized access.', '무단 접근을 방지하기 위해 데이터를 암호화해야 해요.', 'B2', 'technology', 2, 'encryption data security privacy digital', 13),
('col_technology_14', 'scale up', 'operations', 'scale up operations', '운영 규모를 확대하다', 'grow', '"grow operations"도 맞지만 scale up은 기술 스타트업 맥락에서 더 자연스러운 표현이에요.', 'The startup scaled up operations after securing Series B funding.', '그 스타트업은 시리즈 B 투자를 받은 후 운영 규모를 확대했어요.', 'Cloud infrastructure makes it easy to scale up operations quickly.', '클라우드 인프라는 빠르게 운영 규모를 확대하기 쉽게 해줘요.', 'C1', 'technology', 3, 'scale startup growth operations technology', 14),
('col_technology_15', 'access', 'a network', 'access a network', '네트워크에 접속하다', 'connect', '"connect to a network"도 맞지만 access는 네트워크에 들어가는 것을 강조해요.', 'Remote workers can securely access the company network via VPN.', '원격 근무자는 VPN을 통해 회사 네트워크에 안전하게 접속할 수 있어요.', 'She couldn''t access the network because she forgot her password.', '그녀는 비밀번호를 잊어서 네트워크에 접속할 수 없었어요.', 'B1', 'technology', 1, 'network access internet connection technology', 15),
('col_technology_16', 'migrate', 'to the cloud', 'migrate to the cloud', '클라우드로 이전하다', 'move', '"move to the cloud"도 맞지만 migrate는 데이터나 시스템의 공식적인 이전을 강조해요.', 'The company plans to migrate all its data to the cloud by next year.', '회사는 내년까지 모든 데이터를 클라우드로 이전할 계획이에요.', 'Migrating to the cloud can reduce infrastructure costs significantly.', '클라우드로 이전하면 인프라 비용을 크게 줄일 수 있어요.', 'B2', 'technology', 2, 'cloud migration data storage server', 16),
('col_technology_17', 'detect', 'a bug', 'detect a bug', '버그를 발견하다', 'find', '"find a bug"도 맞지만 detect는 자동화된 시스템이나 테스트 도구를 통해 발견하는 뉘앙스예요.', 'The testing software detected a critical bug before the product launched.', '테스팅 소프트웨어는 제품 출시 전에 심각한 버그를 발견했어요.', 'It can be hard to detect bugs in complex software without proper tools.', '적절한 도구 없이 복잡한 소프트웨어에서 버그를 발견하기 어려울 수 있어요.', 'B2', 'technology', 2, 'bug detection software testing code', 17),
('col_technology_18', 'roll out', 'an update', 'roll out an update', '업데이트를 단계적으로 배포하다', 'give', '"give an update"도 맞지만 roll out은 단계적이고 계획적인 배포를 강조해요.', 'The company rolled out the update to users in phases.', '회사는 단계적으로 사용자에게 업데이트를 배포했어요.', 'They plan to roll out the new feature globally next month.', '그들은 다음 달에 전 세계적으로 새 기능을 배포할 계획이에요.', 'C1', 'technology', 3, 'rollout update deployment software release', 18),
('col_technology_19', 'disrupt', 'an industry', 'disrupt an industry', '산업을 혁신하다', 'change', '"change an industry"도 맞지만 disrupt는 기존 질서를 뒤흔드는 혁신적인 변화를 강조해요.', 'Smartphones disrupted the photography industry almost overnight.', '스마트폰은 거의 하룻밤 사이에 사진 산업을 혁신했어요.', 'AI has the potential to disrupt almost every industry in the world.', 'AI는 세계의 거의 모든 산업을 혁신할 잠재력을 가지고 있어요.', 'C1', 'technology', 3, 'disruption innovation industry tech AI', 19),
('col_technology_20', 'harness', 'technology', 'harness technology', '기술을 활용하다', 'use', '"use technology"도 맞지만 harness는 기술의 잠재력을 최대한 활용하는 뉘앙스예요.', 'The organization harnesses technology to deliver better services to its users.', '그 조직은 사용자에게 더 나은 서비스를 제공하기 위해 기술을 활용해요.', 'We need to harness technology responsibly to address global challenges.', '글로벌 과제를 해결하기 위해 기술을 책임감 있게 활용해야 해요.', 'C1', 'technology', 3, 'technology harness innovation solution digital', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_news_01', 'break', 'news', 'break news', '뉴스를 처음 보도하다', 'say', '"say news"는 틀린 표현이에요. 뉴스를 처음 전할 때는 break news 또는 report를 써요.', 'The journalist broke the news of the minister''s resignation.', '기자는 장관의 사임 소식을 처음 보도했어요.', 'It''s always difficult to break bad news to someone.', '누군가에게 나쁜 소식을 처음 전하는 것은 항상 어려워요.', 'B1', 'news', 1, 'news breaking report media journalism', 1),
('col_news_02', 'cover', 'a story', 'cover a story', '기사를 취재하다', 'write', '"write a story"도 맞지만 cover는 취재부터 보도까지의 전 과정을 강조해요.', 'The reporter covered the story from the front lines of the conflict.', '기자는 분쟁 최전선에서 기사를 취재했어요.', 'She has covered major international stories for over 20 years.', '그녀는 20년 이상 주요 국제 기사를 취재해 왔어요.', 'B1', 'news', 1, 'reporter journalist story news media', 2),
('col_news_03', 'publish', 'an article', 'publish an article', '기사를 게재하다', 'put', '"put an article"은 어색해요. 기사를 공식 게재할 때는 publish를 써요.', 'The newspaper published an article exposing corruption in the local government.', '신문은 지방 정부의 부패를 폭로하는 기사를 게재했어요.', 'She published her first article at the age of 22.', '그녀는 22세에 첫 기사를 게재했어요.', 'B1', 'news', 1, 'article publish newspaper media journalism', 3),
('col_news_04', 'report', 'on an event', 'report on an event', '사건을 보도하다', 'tell', '"tell about an event"도 맞지만 report on은 언론의 공식적인 보도를 강조해요.', 'Journalists reported on the protest from multiple viewpoints.', '기자들은 여러 관점에서 시위를 보도했어요.', 'The television crew was on the ground to report on the disaster.', '텔레비전 취재팀이 재해를 보도하기 위해 현장에 있었어요.', 'B1', 'news', 1, 'report event journalism media news', 4),
('col_news_05', 'investigate', 'a claim', 'investigate a claim', '주장을 조사하다', 'check', '"check a claim"도 맞지만 investigate는 더 철저하고 체계적인 조사를 강조해요.', 'The journalist spent months investigating the company''s claims.', '기자는 몇 달 동안 그 회사의 주장을 조사했어요.', 'Editors have a responsibility to investigate claims before publishing.', '편집자들은 게재하기 전에 주장을 조사할 책임이 있어요.', 'B2', 'news', 2, 'investigation journalism claim research fact', 5),
('col_news_06', 'run', 'a headline', 'run a headline', '헤드라인을 싣다', 'write', '"write a headline"도 맞지만 run은 신문이나 방송이 헤드라인을 내보내는 것을 강조해요.', 'The newspaper ran a sensational headline that caused a public outcry.', '신문은 대중의 분노를 야기한 선정적인 헤드라인을 실었어요.', 'All the major papers ran the same headline on their front pages.', '모든 주요 신문이 1면에 동일한 헤드라인을 실었어요.', 'B2', 'news', 2, 'headline newspaper front page media', 6),
('col_news_07', 'confirm', 'a report', 'confirm a report', '보도를 확인하다', 'check', '"check a report"도 맞지만 confirm은 내용의 사실 여부를 공식적으로 확인하는 뉘앙스예요.', 'The spokesperson confirmed the report of the prime minister''s resignation.', '대변인은 총리의 사임에 관한 보도를 확인했어요.', 'Neither the company nor the government would confirm the report.', '회사도 정부도 그 보도를 확인하려 하지 않았어요.', 'B1', 'news', 1, 'confirm report fact official news media', 7),
('col_news_08', 'retract', 'a story', 'retract a story', '기사를 철회하다', 'remove', '"remove a story"도 쓰이지만 retract는 잘못된 정보를 공식적으로 철회하는 뉘앙스예요.', 'The newspaper was forced to retract the story after new evidence emerged.', '신문은 새로운 증거가 나오자 기사를 철회할 수밖에 없었어요.', 'The editor issued an apology when they retracted the false report.', '편집장은 허위 보도를 철회하면서 사과문을 발표했어요.', 'C1', 'news', 3, 'retraction newspaper correction error media', 8),
('col_news_09', 'spread', 'misinformation', 'spread misinformation', '잘못된 정보를 퍼뜨리다', 'share', '"share misinformation"도 맞지만 spread는 정보가 광범위하게 퍼지는 뉘앙스예요.', 'Social media platforms are often used to spread misinformation.', '소셜 미디어 플랫폼은 종종 잘못된 정보를 퍼뜨리는 데 사용돼요.', 'It''s important to verify information before spreading it online.', '온라인에서 정보를 퍼뜨리기 전에 확인하는 것이 중요해요.', 'B2', 'news', 2, 'misinformation social media fake news spread', 9),
('col_news_10', 'fact-check', 'a source', 'fact-check a source', '출처를 팩트체크하다', 'verify', '"verify a source"도 맞지만 fact-check는 뉴스의 사실 여부를 검증하는 특화된 표현이에요.', 'Good journalists fact-check every source before including it in an article.', '좋은 기자들은 기사에 포함하기 전에 모든 출처를 팩트체크해요.', 'Several organisations were set up to fact-check claims made by politicians.', '정치인들의 주장을 팩트체크하기 위해 여러 단체가 설립됐어요.', 'B2', 'news', 2, 'fact check journalism verification truth media', 10),
('col_news_11', 'issue', 'a statement', 'issue a statement', '성명을 발표하다', 'say', '"say a statement"는 어색해요. 공식 성명을 낼 때는 issue 또는 release를 써요.', 'The company issued a statement denying the allegations.', '회사는 혐의를 부인하는 성명을 발표했어요.', 'The government issued a statement urging calm after the incident.', '정부는 사건 후 냉정을 촉구하는 성명을 발표했어요.', 'B2', 'news', 2, 'statement official press release government', 11),
('col_news_12', 'go', 'viral', 'go viral', '바이럴이 되다', 'become', '"become viral"도 쓰이지만 go viral이 훨씬 더 자연스러운 표현이에요.', 'The video of the incident went viral within hours of being posted.', '사건 영상은 게시된 지 몇 시간 만에 바이럴이 됐어요.', 'A single tweet went viral and changed the course of the story.', '하나의 트윗이 바이럴이 돼서 기사의 흐름을 바꿨어요.', 'B1', 'news', 1, 'viral social media internet news trend', 12),
('col_news_13', 'conduct', 'an interview', 'conduct an interview', '인터뷰를 하다', 'do', '"do an interview"도 맞지만 conduct는 더 격식 있고 전문적인 인터뷰를 강조해요.', 'The journalist conducted an interview with the prime minister.', '기자는 총리와 인터뷰를 했어요.', 'She has conducted thousands of interviews over her 30-year career.', '그녀는 30년 경력 동안 수천 건의 인터뷰를 했어요.', 'B1', 'news', 1, 'interview journalist media news conduct', 13),
('col_news_14', 'cite', 'a source', 'cite a source', '출처를 인용하다', 'name', '"name a source"도 맞지만 cite는 공식적으로 출처를 명시하는 뉘앙스예요.', 'The report cited anonymous sources within the government.', '그 보도는 정부 내 익명의 출처를 인용했어요.', 'Always cite your sources to maintain journalistic credibility.', '언론의 신뢰성을 유지하기 위해 항상 출처를 인용하세요.', 'B2', 'news', 2, 'source citation reference journalism media', 14),
('col_news_15', 'raise', 'a concern', 'raise a concern', '우려를 제기하다', 'say', '"say a concern"은 어색해요. 우려 사항을 공식적으로 언급할 때는 raise를 써요.', 'The report raised serious concerns about data privacy.', '그 보도는 데이터 프라이버시에 대한 심각한 우려를 제기했어요.', 'Several journalists raised concerns about editorial independence.', '여러 기자들이 편집 독립에 대한 우려를 제기했어요.', 'B2', 'news', 2, 'concern news report media issue', 15),
('col_news_16', 'lead', 'with a story', 'lead with a story', '기사를 첫 번째로 다루다', 'start', '"start with a story"도 맞지만 lead with는 편집 결정으로 첫 뉴스로 다루는 뉘앙스예요.', 'The evening news led with the story of the earthquake.', '저녁 뉴스는 지진 기사를 첫 번째로 다뤘어요.', 'Most news channels led with the same story about the election result.', '대부분의 뉴스 채널이 선거 결과에 관한 동일한 기사를 첫 번째로 다뤘어요.', 'C1', 'news', 3, 'headline lead news broadcast editorial', 16),
('col_news_17', 'uncover', 'a scandal', 'uncover a scandal', '스캔들을 폭로하다', 'find', '"find a scandal"도 맞지만 uncover는 숨겨진 것을 드러내는 뉘앙스예요.', 'The investigative team uncovered a major political scandal.', '탐사보도팀은 대규모 정치 스캔들을 폭로했어요.', 'The reporter uncovered the scandal after months of investigation.', '기자는 몇 달간의 조사 끝에 스캔들을 폭로했어요.', 'B2', 'news', 2, 'scandal uncover investigation journalism reveal', 17),
('col_news_18', 'balance', 'coverage', 'balance coverage', '균형 있게 보도하다', 'control', '"control coverage"는 어색해요. 공정한 보도를 위해서는 balance coverage를 써요.', 'A responsible journalist always balances coverage of both sides.', '책임감 있는 기자는 항상 양측을 균형 있게 보도해요.', 'Critics argued the channel failed to balance its coverage of the election.', '비평가들은 그 채널이 선거 보도를 균형 있게 하지 못했다고 주장했어요.', 'C1', 'news', 3, 'balance media coverage fair journalism', 18),
('col_news_19', 'quote', 'a source', 'quote a source', '출처를 인용하다', 'use', '"use a source"도 맞지만 quote는 출처의 말을 그대로 인용하는 것을 강조해요.', 'The article quoted a senior official who asked to remain anonymous.', '그 기사는 익명을 요청한 고위 관료를 인용했어요.', 'Journalists must ensure they quote sources accurately.', '기자들은 출처를 정확하게 인용해야 해요.', 'B1', 'news', 1, 'quote source journalism media reference', 19),
('col_news_20', 'hold', 'a press conference', 'hold a press conference', '기자회견을 열다', 'make', '"make a press conference"는 어색해요. 기자회견을 개최할 때는 hold를 써요.', 'The prime minister held a press conference to address the allegations.', '총리는 혐의에 대해 해명하기 위해 기자회견을 열었어요.', 'The company held a press conference to announce the merger.', '회사는 합병을 발표하기 위해 기자회견을 열었어요.', 'B1', 'news', 1, 'press conference media journalism official announcement', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_academic_01', 'submit', 'an essay', 'submit an essay', '에세이를 제출하다', 'give', '"give an essay"는 어색해요. 과제를 제출할 때는 submit 또는 hand in을 써요.', 'Students must submit their essays by midnight on Friday.', '학생들은 금요일 자정까지 에세이를 제출해야 해요.', 'She submitted her essay a day early to avoid last-minute stress.', '그녀는 마지막 순간의 스트레스를 피하기 위해 하루 일찍 에세이를 제출했어요.', 'B1', 'academic', 1, 'essay submit university assignment deadline', 1),
('col_academic_02', 'attend', 'a lecture', 'attend a lecture', '강의에 참석하다', 'go', '"go to a lecture"도 맞지만 attend는 더 격식 있는 표현이에요.', 'She attended every lecture despite having a part-time job.', '그녀는 아르바이트를 하면서도 모든 강의에 참석했어요.', 'Students who attend lectures regularly tend to perform better in exams.', '강의에 규칙적으로 참석하는 학생들은 시험에서 더 좋은 성과를 내는 경향이 있어요.', 'B1', 'academic', 1, 'lecture university class attend study', 2),
('col_academic_03', 'take', 'notes', 'take notes', '필기하다', 'write', '"write notes"도 맞지만 take notes는 수업 중에 필기하는 것을 강조해요.', 'He always takes detailed notes during lectures.', '그는 항상 강의 중에 자세한 필기를 해요.', 'Taking good notes helps you review the material more effectively.', '좋은 필기를 하면 내용을 더 효과적으로 복습할 수 있어요.', 'A2', 'academic', 1, 'notes study lecture writing class', 3),
('col_academic_04', 'pass', 'an exam', 'pass an exam', '시험에 합격하다', 'succeed', '"succeed in an exam"도 맞지만 pass an exam이 훨씬 더 자연스러운 표현이에요.', 'She worked very hard and passed all her exams with distinction.', '그녀는 매우 열심히 공부해서 모든 시험에 우수한 성적으로 합격했어요.', 'You need to pass the exam to qualify for the next level.', '다음 단계로 진급하려면 시험에 합격해야 해요.', 'B1', 'academic', 1, 'exam pass study success university', 4),
('col_academic_05', 'enrol in', 'a course', 'enrol in a course', '과정에 등록하다', 'join', '"join a course"도 쓰이지만 enrol in은 공식적인 등록 절차를 강조해요.', 'She enrolled in an online course to improve her academic writing.', '그녀는 학문적 글쓰기를 향상시키기 위해 온라인 과정에 등록했어요.', 'How many students enrolled in the linguistics course this year?', '올해 언어학 과정에 몇 명의 학생이 등록했어요?', 'B1', 'academic', 1, 'enrolment course university study registration', 5),
('col_academic_06', 'write', 'a thesis', 'write a thesis', '논문을 쓰다', 'make', '"make a thesis"는 어색해요. 학위 논문을 작성할 때는 write a thesis를 써요.', 'He spent two years writing his doctoral thesis.', '그는 박사 학위 논문을 쓰는 데 2년을 보냈어요.', 'Writing a thesis requires strong research and critical thinking skills.', '논문을 쓰는 것은 강한 연구 및 비판적 사고 능력을 요구해요.', 'B2', 'academic', 2, 'thesis research writing university graduate', 6),
('col_academic_07', 'earn', 'a degree', 'earn a degree', '학위를 취득하다', 'get', '"get a degree"도 맞지만 earn은 노력을 통해 성취한다는 뉘앙스예요.', 'She earned a degree in computer science from Seoul National University.', '그녀는 서울대학교에서 컴퓨터공학 학위를 취득했어요.', 'He earned his degree while working full-time at a technology company.', '그는 기술 회사에서 전일제로 일하면서 학위를 취득했어요.', 'B1', 'academic', 1, 'degree university graduation achievement education', 7),
('col_academic_08', 'review', 'the literature', 'review the literature', '문헌을 검토하다', 'read', '"read the literature"도 맞지만 review는 비판적으로 검토하고 종합하는 뉘앙스예요.', 'The first step in any research project is to review the existing literature.', '모든 연구 프로젝트의 첫 번째 단계는 기존 문헌을 검토하는 것이에요.', 'She reviewed the literature to identify gaps in current research.', '그녀는 현재 연구의 공백을 파악하기 위해 문헌을 검토했어요.', 'B2', 'academic', 2, 'literature review research academic study', 8),
('col_academic_09', 'formulate', 'a hypothesis', 'formulate a hypothesis', '가설을 세우다', 'make', '"make a hypothesis"도 쓰이지만 formulate는 더 체계적이고 논리적인 과정을 강조해요.', 'The scientist formulated a hypothesis based on her preliminary observations.', '과학자는 예비 관찰을 바탕으로 가설을 세웠어요.', 'Students must formulate a clear hypothesis before beginning their experiments.', '학생들은 실험을 시작하기 전에 명확한 가설을 세워야 해요.', 'B2', 'academic', 2, 'hypothesis science research experiment study', 9),
('col_academic_10', 'apply', 'for a scholarship', 'apply for a scholarship', '장학금을 신청하다', 'get', '"get a scholarship"도 맞지만 apply for는 신청 과정을 강조해요. 먼저 신청해야 받을 수 있어요.', 'She applied for a scholarship to fund her postgraduate studies.', '그녀는 대학원 학업 자금을 마련하기 위해 장학금을 신청했어요.', 'You should apply for as many scholarships as you are eligible for.', '자격이 되는 장학금에 최대한 많이 신청해야 해요.', 'B1', 'academic', 1, 'scholarship university funding apply education', 10),
('col_academic_11', 'sit', 'an exam', 'sit an exam', '시험을 치르다', 'take', '"take an exam"도 맞고 자주 쓰여요. sit an exam은 영국 영어에서 더 격식 있게 쓰여요.', 'Students must sit the final exam in the examination hall.', '학생들은 시험장에서 최종 시험을 치러야 해요.', 'She sat the entrance exam three times before passing.', '그녀는 합격하기까지 입학시험을 세 번 치렀어요.', 'B2', 'academic', 2, 'exam university test hall formal', 11),
('col_academic_12', 'plagiarise', 'work', 'plagiarise work', '작업물을 표절하다', 'copy', '"copy work"도 맞지만 plagiarise는 다른 사람의 작업을 자신의 것처럼 제출하는 구체적인 행위예요.', 'Students who plagiarise work face serious academic consequences.', '작업물을 표절한 학생들은 심각한 학문적 결과에 직면해요.', 'Always cite your sources — plagiarising even a paragraph is unacceptable.', '항상 출처를 인용하세요. 단 하나의 단락을 표절하는 것도 용납되지 않아요.', 'C1', 'academic', 3, 'plagiarism academic integrity essay university', 12),
('col_academic_13', 'defend', 'a thesis', 'defend a thesis', '논문을 구두 심사에서 발표하다', 'present', '"present a thesis"도 맞지만 defend는 심사위원의 질문에 답하는 구두 시험을 강조해요.', 'She successfully defended her thesis in front of a panel of professors.', '그녀는 교수 심사 패널 앞에서 논문을 성공적으로 발표했어요.', 'Defending your thesis is one of the most challenging parts of a PhD.', '논문 구두 심사는 박사 과정에서 가장 도전적인 부분 중 하나예요.', 'C1', 'academic', 3, 'thesis defense PhD university examination', 13),
('col_academic_14', 'meet', 'a deadline', 'meet a deadline', '마감 기한을 맞추다', 'do', '"do a deadline"은 틀린 표현이에요. 마감 기한을 지킬 때는 meet a deadline을 써요.', 'She struggled to meet the deadline for her research paper.', '그녀는 연구 논문의 마감 기한을 맞추기 위해 애썼어요.', 'Good time management is essential if you want to meet every deadline.', '모든 마감 기한을 맞추고 싶다면 좋은 시간 관리가 필수예요.', 'B1', 'academic', 1, 'deadline time management university assignment', 14),
('col_academic_15', 'score', 'high marks', 'score high marks', '높은 점수를 받다', 'get', '"get high marks"도 맞지만 score는 시험이나 과제에서 특정 점수를 얻는 것을 강조해요.', 'She scored the highest marks in the class on the final exam.', '그녀는 기말고사에서 반에서 가장 높은 점수를 받았어요.', 'Hard work and preparation are the keys to scoring high marks.', '열심히 공부하고 준비하는 것이 높은 점수를 받는 열쇠예요.', 'B1', 'academic', 1, 'marks score exam grade university', 15),
